#!/usr/bin/env python3
"""EVE Online Industrial Planner - Parse SDE and emit recipe reports."""

import argparse
import bz2
import csv
import math
import sys
from pathlib import Path
from collections import defaultdict
from dataclasses import dataclass
from typing import Optional

import yaml


def load_csv_bz2(filepath: Path):
    with bz2.open(filepath, 'rt', encoding='utf-8') as f:
        return list(csv.DictReader(f))


def load_yaml_file(filepath: Path):
    with open(filepath, 'r', encoding='utf-8') as f:
        return yaml.safe_load(f)


@dataclass
class BuildParams:
    item_name: str
    runs_per_job: int
    num_jobs: int
    me: int = 0
    te: int = 0
    decryptor: str = 'None'
    relic: Optional[str] = None
    build_type: str = 'normal'


@dataclass
class SDEData:
    types: dict = field(default_factory=dict)
    groups: dict = field(default_factory=dict)
    categories: dict = field(default_factory=dict)
    market_groups: dict = field(default_factory=dict)
    meta_types: dict = field(default_factory=dict)
    meta_groups: dict = field(default_factory=dict)
    activities: dict = field(default_factory=lambda: defaultdict(dict))
    products: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(dict)))
    materials: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(list)))
    probabilities: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(dict)))
    skills: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(list)))
    activity_names: dict = field(default_factory=dict)
    ship_volumes: dict = field(default_factory=dict)
    buildable_types: set = field(default_factory=set)
    inventable_by_product: dict = field(default_factory=dict)
    blueprint_names: dict = field(default_factory=dict)


def parse_sde(sde_dir: Path) -> SDEData:
    data = SDEData()

    for row in load_csv_bz2(sde_dir / 'invTypes.csv.bz2'):
        if int(row.get('published', 0)) != 1:
            continue
        tid = int(row['typeID'])
        data.types[tid] = {
            'typeID': tid,
            'groupID': int(row['groupID']),
            'typeName': row['typeName'],
            'volume': row.get('volume', '0'),
            'marketGroupID': int(row['marketGroupID']) if row.get('marketGroupID') and row['marketGroupID'] != 'None' else None,
            'mass': row.get('mass', '0'),
            'raceID': row.get('raceID'),
            'basePrice': row.get('basePrice'),
            'description': row.get('description', ''),
        }

    for row in load_csv_bz2(sde_dir / 'invGroups.csv.bz2'):
        if int(row.get('published', 0)) != 1:
            continue
        gid = int(row['groupID'])
        data.groups[gid] = {
            'groupID': gid,
            'categoryID': int(row['categoryID']),
            'groupName': row['groupName'],
            'iconID': row.get('iconID'),
        }

    for row in load_csv_bz2(sde_dir / 'invCategories.csv.bz2'):
        if int(row.get('published', 0)) != 1:
            continue
        cid = int(row['categoryID'])
        data.categories[cid] = {
            'categoryID': cid,
            'categoryName': row['categoryName'],
            'iconID': row.get('iconID'),
        }

    for row in load_csv_bz2(sde_dir / 'invMarketGroups.csv.bz2'):
        mg_id = int(row['marketGroupID'])
        parent_id = int(row['parentGroupID']) if row.get('parentGroupID') and row['parentGroupID'] != 'None' else None
        data.market_groups[mg_id] = {
            'marketGroupID': mg_id,
            'parentGroupID': parent_id,
            'marketGroupName': row['marketGroupName'],
            'description': row.get('description', ''),
            'iconID': row.get('iconID'),
            'hasTypes': int(row.get('hasTypes', 0)) == 1,
        }

    for row in load_csv_bz2(sde_dir / 'invMetaTypes.csv.bz2'):
        if row.get('metaGroupID'):
            data.meta_types[int(row['typeID'])] = int(row['metaGroupID'])

    for row in load_csv_bz2(sde_dir / 'invMetaGroups.csv.bz2'):
        data.meta_groups[int(row['metaGroupID'])] = row['metaGroupName']

    for row in load_csv_bz2(sde_dir / 'industryActivity.csv.bz2'):
        data.activities[int(row['typeID'])][int(row['activityID'])] = int(row['time'])

    for row in load_csv_bz2(sde_dir / 'industryActivityProducts.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        pid = int(row['productTypeID'])
        data.products[tid][aid][pid] = int(row['quantity'])

    for row in load_csv_bz2(sde_dir / 'industryActivityMaterials.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        data.materials[tid][aid].append({'typeID': int(row['materialTypeID']), 'quantity': int(row['quantity'])})

    for row in load_csv_bz2(sde_dir / 'industryActivityProbabilities.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        pid = int(row['productTypeID'])
        data.probabilities[tid][aid][pid] = float(row['probability'])

    for row in load_csv_bz2(sde_dir / 'industryActivitySkills.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        data.skills[tid][aid].append({'skillID': int(row['skillID']), 'level': int(row['level'])})

    for row in load_csv_bz2(sde_dir / 'ramActivities.csv.bz2'):
        if row.get('published') == '1':
            data.activity_names[int(row['activityID'])] = row['activityName']

    data.ship_volumes = {k: float(v) for k, v in load_yaml_file(sde_dir / 'ship_volumes.yaml').items()}

    for tid, acts in data.products.items():
        if 1 in acts or 8 in acts:
            data.buildable_types.add(tid)
        if 8 in acts:
            for pid in acts[8]:
                data.inventable_by_product[pid] = (tid, 8)

    for tid, tdata in data.types.items():
        if 'Blueprint' in tdata['typeName']:
            data.blueprint_names[tdata['typeName']] = tid

    return data


INVENTION = 8
MANUFACTURING = 1


def get_type_name(data: SDEData, tid: int) -> str:
    return data.types.get(tid, {}).get('typeName', '')


def get_group_path(data: SDEData, tid: int):
    tdata = data.types.get(tid)
    if not tdata:
        return 'Unknown', 'Unknown'
    gdata = data.groups.get(tdata['groupID'])
    if not gdata:
        return 'Unknown', 'Unknown'
    if cdata := data.categories.get(gdata['categoryID']):
        return cdata['categoryName'], gdata['groupName']
    return 'Unknown', gdata['groupName']


def get_market_group_path(data: SDEData, tid: int):
    tdata = data.types.get(tid)
    if not tdata or not tdata.get('marketGroupID'):
        return None
    path_parts = []
    mg_id = tdata['marketGroupID']
    while mg_id is not None:
        mgdata = data.market_groups.get(mg_id)
        if not mgdata:
            break
        path_parts.append(mgdata['marketGroupName'])
        mg_id = mgdata.get('parentGroupID')
    return ' > '.join(reversed(path_parts)) if path_parts else None


def get_tech_level(data: SDEData, tid: int) -> str:
    meta_id = data.meta_types.get(tid)
    if not meta_id:
        return 'Tech I'
    meta_name = data.meta_groups.get(meta_id, '')
    return meta_name if meta_name in ('Tech II', 'Tech III') else 'Tech I'


def get_volume(data: SDEData, tid: int) -> float:
    tdata = data.types.get(tid)
    if not tdata:
        return 0.0
    _, gname = get_group_path(data, tid)
    if gname in data.ship_volumes:
        return data.ship_volumes[gname]
    try:
        return float(tdata.get('volume') or '0')
    except ValueError:
        return 0.0


def get_invention_data(data: SDEData, pid: int, skill_level: int) -> Optional[dict]:
    bid, _ = data.inventable_by_product.get(pid, (None, None))
    if not bid:
        return None

    time_minutes = math.ceil(data.activities.get(bid, {}).get(INVENTION, 0) / 60)

    dc_materials = data.materials.get(bid, {}).get(INVENTION, [])
    datacores = []
    for mat in dc_materials:
        mname = get_type_name(data, mat['typeID'])
        if mname and mname.startswith('Datacore - '):
            datacores.append({'typeID': mat['typeID'], 'name': mname, 'quantity': mat['quantity']})

    skill_list = data.skills.get(bid, {}).get(INVENTION, [])
    skills = [{'name': get_type_name(data, s['skillID']), 'required_level': s['level']} for s in skill_list]

    base_prob = data.probabilities.get(bid, {}).get(INVENTION, {}).get(pid, 0.0)

    return {
        'invention_blueprint_id': bid,
        'time_minutes': time_minutes,
        'datacores': datacores,
        'skills': skills,
        'base_probability': base_prob,
        'tech_level': get_tech_level(data, pid)
    }


def get_recipe(data: SDEData, tid: int, me: int = 0) -> Optional[dict]:
    acts = data.products.get(tid, {})
    if MANUFACTURING not in acts:
        return None

    time_raw = data.activities.get(tid, {}).get(MANUFACTURING, 0)
    materials = data.materials.get(tid, {}).get(MANUFACTURING, [])

    if me > 0:
        materials = [{'typeID': m['typeID'], 'quantity': math.ceil(max(1, m['quantity'] * (1 - me / 100))), 'original_quantity': m['quantity']} for m in materials]
    else:
        materials = [{'typeID': m['typeID'], 'quantity': m['quantity'], 'original_quantity': m['quantity']} for m in materials]

    return {
        'activity': data.activity_names.get(MANUFACTURING, 'Manufacturing'),
        'output_qty': sum(acts[MANUFACTURING].values()),
        'run_time': round(time_raw / 60),
        'materials': materials
    }


def find_product_by_name(data: SDEData, name: str, bp_lookup: bool = True):
    for tid, tdata in data.types.items():
        if tdata['typeName'] == name:
            return tdata, tid, False
    if bp_lookup:
        for bp_name, bid in data.blueprint_names.items():
            if bp_name == name:
                return data.types.get(bid), bid, True
    return None, None, False


def calculate_probability(base_prob: float, skill_level: int, decryptor: str) -> float:
    mult = base_prob * (1 + 7 * skill_level / 120)
    dec = DECRYPTORS.get(decryptor, (0, 0, 0, 0))
    return max(0.0, min(1.0, mult * (1 + dec[0] / 100.0)))


DECRYPTORS = {
    'None': (0, 0, 0, 0),
    'Accelerant Decryptor': (20, 1, 2, 10),
    'Attainment Decryptor': (80, 4, -1, 4),
    'Augmentation Decryptor': (-40, 9, -2, 2),
    'Optimized Attainment Decryptor': (90, 2, 1, -2),
    'Optimized Augmentation Decryptor': (-10, 7, 2, 0),
    'Parity Decryptor': (50, 3, 1, -2),
    'Process Decryptor': (10, 0, 3, 6),
    'Symmetry Decryptor': (0, 2, 1, 8),
}

TECHIII_RELICS = {'Intact': 0.26, 'Malfunctioning': 0.21, 'Wrecked': 0.14}
TECHIII_BASE_RUNS = {'Intact': 20, 'Malfunctioning': 10, 'Wrecked': 3}


def parse_build_string(build_str: str) -> BuildParams:
    parts = build_str.strip().split()
    if len(parts) < 2:
        raise ValueError(f"Invalid build string format: {build_str}")

    num_jobs = 1
    x_idx = next((i for i, p in enumerate(parts) if p.lower().startswith('x')), -1)
    if x_idx >= 0:
        num_jobs = int(parts[x_idx][1:])
        parts = parts[:x_idx] + parts[x_idx+1:]

    # Find first numeric token
    first_num = next((i for i, p in enumerate(parts) if p.isdigit()), -1)
    if first_num <= 0:
        raise ValueError(f"Invalid build string format: {build_str}")

    item_name = ' '.join(parts[:first_num])
    tokens = parts[first_num:]

    if len(tokens) == 1:
        return BuildParams(item_name, int(tokens[0]), num_jobs)
    if len(tokens) == 2:
        try:
            return BuildParams(item_name, int(tokens[0]), num_jobs, me=int(tokens[1]))
        except ValueError:
            return BuildParams(item_name, int(tokens[0]), num_jobs, decryptor=tokens[1], build_type='invention')
    if len(tokens) == 3:
        return BuildParams(item_name, int(tokens[0]), num_jobs, me=int(tokens[1]), te=int(tokens[2]))
    if len(tokens) == 4:
        return BuildParams(item_name, int(tokens[0]), num_jobs, decryptor=tokens[1], relic=tokens[2], build_type='re')

    raise ValueError(f"Invalid build string format. Unexpected argument count: {build_str}")


def generate_invention_report(data: SDEData, name: str, skill: int) -> str:
    tdata, tid, is_bp = find_product_by_name(data, name)
    if not tdata:
        return f"Error: Item '{name}' not found or not published.\n"

    if is_bp:
        inv = data.products.get(tid, {}).get(INVENTION, {})
        if inv:
            tid = next(iter(inv.keys()))
            tdata = data.types.get(tid)
        else:
            return f"Error: '{name}' is not an inventable blueprint.\n"

    inv = get_invention_data(data, tid, skill)
    if not inv:
        return f"Error: '{name}' is not an inventable item.\n"

    tech = inv['tech_level']
    if tech not in ('Tech II', 'Tech III'):
        return f"Error: '{name}' is not Tech II or Tech III.\n"

    cat, grp = get_group_path(data, tid)
    mg = get_market_group_path(data, tid)

    lines = [
        f"ITEM: {tdata['typeName']} ({tid})",
        f"Group: {cat} > {grp}",
        f"Market Group: {mg if mg else 'None'}",
        f"Tech Level: {tech}",
        "",
        "Invention:",
    ]

    if tech == 'Tech II':
        lines.append(f"Base: {get_type_name(data, inv['invention_blueprint_id'])} ({inv['invention_blueprint_id']})")

    dc = sorted(inv['datacores'], key=lambda d: d['name'].lower())
    lines.append(f"Datacores: {', '.join(d['name'] for d in dc)}")
    lines.append(f"Required Per Run: {dc[0]['quantity'] if dc else 0}")

    sk = sorted(inv['skills'], key=lambda s: s['name'].lower())
    lines.append(f"Skills: {', '.join(s['name'] for s in sk)}")
    lines.append(f"Time: {inv['time_minutes']}")

    if tech == 'Tech II':
        base_bp = inv['invention_blueprint_id']
        base_runs = data.products.get(base_bp, {}).get(INVENTION, {}).get(tid, 10)
        lines.extend(["Probabilities:", "| Decryptor                       | Probability | Runs | ME | TE |", "|---------------------------------|-------------|------|----|----|"])
        for dname in sorted(DECRYPTORS.keys(), key=str.lower):
            prob = calculate_probability(inv['base_probability'], skill, dname)
            _, dr, dme, dte = DECRYPTORS[dname]
            lines.append(f"| {dname:<31} | {prob:>9.2f} | {base_runs + dr:>4} | {2 + dme:>2} | {4 + dte:>2} |")
    else:
        lines.extend(["Probabilities:", "| Invented From                | Decryptor                       | Probability | Runs | ME | TE |", "|------------------------------|---------------------------------|-------------|------|----|----|"])
        for rel in ('Intact', 'Malfunctioning', 'Wrecked'):
            for dname in sorted(DECRYPTORS.keys(), key=str.lower):
                prob = calculate_probability(TECHIII_RELICS[rel], skill, dname)
                _, dr, dme, dte = DECRYPTORS[dname]
                lines.append(f"| {rel:<28} | {dname:<31} | {prob:>9.2f} | {TECHIII_BASE_RUNS[rel] + dr:>4} | {2 + dme:>2} | {4 + dte:>2} |")

    return '\n'.join(lines) + '\n'


def write_jobs_csv(path: Path, name: str, runs: int, days: float, count: int):
    with open(path, 'w', newline='', encoding='utf-8') as f:
        w = csv.writer(f)
        w.writerow(['name', 'runs', 'days', 'count'])
        w.writerow([name, runs, days, count])


def write_materials_csv(path: Path, mat_data: dict):
    with open(path, 'w', newline='', encoding='utf-8') as f:
        w = csv.writer(f)
        w.writerow(['name', 'to_buy', 'buy_volume', 'start_amount', 'end_amount'])
        for name in sorted(mat_data.keys()):
            qty = mat_data[name]
            w.writerow([name, qty, round(qty / 10, 1), 0, 0])


def resolve_blueprint_product(data: SDEData, bid: int):
    for pid, acts in data.products.items():
        if pid == bid:
            for act in acts.values():
                if act:
                    product_id = next(iter(act.keys()))
                    return product_id, data.types.get(product_id)
    return None, None


def generate_plan(data: SDEData, params: BuildParams, config: dict, out_dir: Path) -> str:
    out_dir.mkdir(parents=True, exist_ok=True)

    tdata, tid, found_bp = find_product_by_name(data, params.item_name)
    if not tdata:
        return f"Error: Item '{params.item_name}' not found or not published.\n"

    bid = tid if found_bp else None
    if bid:
        tid, tdata = resolve_blueprint_product(data, bid)
        if not tid:
            return f"Error: No product found for blueprint.\n"

    if params.build_type in ('invention', 're'):
        return _gen_invention_plan(data, params, config, out_dir, tid, bid)
    return _gen_manufacturing_plan(data, params, config, out_dir, tid, bid)


def _gen_invention_plan(data: SDEData, params: BuildParams, config: dict, out_dir: Path, tid: int, bid: int):
    inv = get_invention_data(data, tid, config.get('invention_skill', 3))
    if not inv:
        return f"Error: item not inventable.\n"

    prob = calculate_probability(inv['base_probability'], config.get('invention_skill', 3), params.decryptor)
    _, dr, _, _ = DECRYPTORS.get(params.decryptor, (0, 0, 0, 0))

    rel = params.relic or 'Malfunctioning'
    base_runs = TECHIII_BASE_RUNS.get(rel, 10) if params.build_type == 're' else data.products.get(inv['invention_blueprint_id'], {}).get(INVENTION, {}).get(tid, 10)
    runs = base_runs + dr

    total_runs = params.num_jobs * params.runs_per_job
    exp_bp_runs = math.ceil(total_runs / (runs * prob))

    dc_materials = data.materials.get(inv['invention_blueprint_id'], {}).get(INVENTION, [])
    dc_data = {}
    for mat in dc_materials:
        mname = get_type_name(data, mat['typeID'])
        if mname and mname.startswith('Datacore - '):
            dc_data[mname] = dc_data.get(mname, 0) + mat['quantity'] * exp_bp_runs

    write_materials_csv(out_dir / 'materials.csv', dc_data)

    invent_time = inv['time_minutes'] * exp_bp_runs
    bp_name = get_type_name(data, inv['invention_blueprint_id']) or f"Blueprint {inv['invention_blueprint_id']}"
    write_jobs_csv(out_dir / 'jobs.csv', f"{bp_name} Blueprints", exp_bp_runs, math.ceil(invent_time / 60 / 24 * 100) / 100, 1)

    return f"Plan generated: {out_dir / 'materials.csv'}, {out_dir / 'jobs.csv'}\n"


def _gen_manufacturing_plan(data: SDEData, params: BuildParams, config: dict, out_dir: Path, tid: int, bid: int):
    # Find blueprint if not provided
    if not bid:
        for pid, acts in data.products.items():
            if MANUFACTURING in acts and tid in acts[MANUFACTURING]:
                bid = pid
                break
        if not bid:
            return f"Error: No manufacturing blueprint found.\n"

    bp_time = data.activities.get(bid, {}).get(MANUFACTURING, 0)
    if bp_time == 0:
        bp_time = data.activities.get(tid, {}).get(MANUFACTURING, 0)

    te_bonus = config.get('te_bonus', 20)
    full_te = bp_time * (1 - params.te / 100) * (1 - te_bonus / 100)
    run_days = full_te / 60 / 24

    materials = [{'typeID': m['typeID'], 'quantity': math.ceil(max(1, m['quantity'] * (1 - params.me / 100))), 'original_quantity': m['quantity']} for m in data.materials.get(bid, {}).get(MANUFACTURING, [])]

    total_runs = params.num_jobs * params.runs_per_job
    mat_total = {}
    for mat in materials:
        name = get_type_name(data, mat['typeID']) or f'Type {mat["typeID"]}'
        mat_total[name] = mat_total.get(name, 0) + mat['quantity'] * total_runs

    write_materials_csv(out_dir / 'materials.csv', mat_total)

    bp_name = get_type_name(data, bid) or f"Blueprint {bid}"
    with open(out_dir / 'jobs.csv', 'w', newline='', encoding='utf-8') as f:
        w = csv.writer(f)
        w.writerow(['name', 'runs', 'days', 'count'])
        for j in range(1, params.num_jobs + 1):
            w.writerow([bp_name, params.runs_per_job, round(run_days * params.runs_per_job, 2), j])

    return f"Plan generated: {out_dir / 'materials.csv'}, {out_dir / 'jobs.csv'}\n"


def generate_report(data: SDEData, name: str, me: int = 0, te: int = 0, waste: bool = False) -> str:
    tdata, tid, found_bp = find_product_by_name(data, name)
    if not tdata:
        return f"Error: Item '{name}' not found or not published.\n"

    bid = tid if found_bp else None
    disp_tid, disp_tdata = tid, tdata
    if bid:
        disp_tid, disp_tdata = resolve_blueprint_product(data, bid) or (tid, tdata)

    recipe = get_recipe(data, disp_tid, me)
    if not recipe:
        return f"Error: No industry activity found for '{name}'.\n"

    cat, grp = get_group_path(data, disp_tid)
    mg = get_market_group_path(data, disp_tid)
    tech = get_tech_level(data, disp_tid)
    vol = get_volume(data, disp_tid)

    run_time = round(recipe['run_time'] * (1 - te / 100)) if te > 0 else recipe['run_time']

    def mat_row(m):
        mname = get_type_name(data, m['typeID']) or 'Unknown'
        buildable = 'Yes' if any(a in data.buildable_types for a in [m['typeID']]) else 'No'
        if waste:
            return f"| {mname} | {m['quantity']} | {m['original_quantity'] - m['quantity']} | {buildable} |"
        return f"| {mname} | {m['quantity']} | {buildable} |"

    header = "| Item | Quantity | Waste | Buildable |" if waste else "| Item | Quantity | Buildable |"
    sep = "|:-:|:-:|:-:|---:|" if waste else "|:-:|:---:|---:|"

    lines = [
        f"ITEM: {disp_tdata['typeName']} ({disp_tid})",
        f"Group: {cat} > {grp}",
        f"Market Group: {mg if mg else 'None'}",
        f"Tech Level: {tech}",
        f"Volume: {vol:.2f}",
        "",
        "Recipe:",
        f"Activity: {recipe['activity']}",
        f"Output Quantity: {recipe['output_qty']}",
        f"Run Time: {run_time}",
        header,
        sep,
    ]
    for mat in sorted(recipe['materials'], key=lambda m: (get_type_name(data, m['typeID']) or '').lower()):
        lines.append(mat_row(mat))

    return '\n'.join(lines) + '\n'


def main():
    p = argparse.ArgumentParser(description='EVE Online Industrial Planner')
    s = p.add_subparsers(dest='command')

    r = s.add_parser('recipe', help='Generate recipe report')
    r.add_argument('target')
    r.add_argument('--sde', required=True)
    r.add_argument('--me', type=int, default=0)
    r.add_argument('--te', type=int, default=0)
    r.add_argument('--waste', action='store_true')

    inv = s.add_parser('invention', help='Generate invention report')
    inv.add_argument('target')
    inv.add_argument('--sde', required=True)
    inv.add_argument('--skill', type=int, choices=range(1, 6), default=5)

    pl = s.add_parser('plan', help='Create build plan')
    pl.add_argument('build_string')
    pl.add_argument('--config', required=True)
    pl.add_argument('--sde', required=True)
    pl.add_argument('--output', required=True)

    args = p.parse_args()
    if not args.command:
        p.print_help()
        sys.exit(1)

    sde_path = Path(args.sde)
    if not sde_path.exists():
        print(f"Error: SDE '{args.sde}' not found.", file=sys.stderr)
        sys.exit(1)

    d = parse_sde(sde_path)

    if args.command == 'recipe':
        if not 0 <= args.me <= 10:
            print(f"Error: ME must be 0-10, got {args.me}", file=sys.stderr)
            sys.exit(1)
        if not 0 <= args.te <= 20 or args.te % 2 != 0:
            print(f"Error: TE must be even 0-20, got {args.te}", file=sys.stderr)
            sys.exit(1)
        print(generate_report(d, args.target, args.me, args.te, args.waste), end='')
    elif args.command == 'invention':
        print(generate_invention_report(d, args.target, args.skill), end='')
    elif args.command == 'plan':
        try:
            params = parse_build_string(args.build_string)
        except ValueError as e:
            print(f"Error: {e}", file=sys.stderr)
            sys.exit(1)
        cfg = load_yaml_file(Path(args.config))
        print(generate_plan(d, params, cfg, Path(args.output)), end='')


if __name__ == '__main__':
    main()

#!/usr/bin/env python3
"""EVE Online Industrial Planner - Parse SDE and emit recipe reports."""

import argparse
import bz2
import csv
import math
import sys
from pathlib import Path
from collections import defaultdict
from dataclasses import dataclass
from typing import Optional, field

import yaml


def load_csv_bz2(filepath: Path):
    with bz2.open(filepath, 'rt', encoding='utf-8') as f:
        return list(csv.DictReader(f))


def load_yaml_file(filepath: Path):
    with open(filepath, 'r', encoding='utf-8') as f:
        return yaml.safe_load(f)


@dataclass
class BuildParams:
    item_name: str
    runs_per_job: int
    num_jobs: int
    me: int = 0
    te: int = 0
    decryptor: str = 'None'
    relic: Optional[str] = None
    build_type: str = 'normal'


@dataclass
class SDEData:
    types: dict = field(default_factory=dict)
    groups: dict = field(default_factory=dict)
    categories: dict = field(default_factory=dict)
    market_groups: dict = field(default_factory=dict)
    meta_types: dict = field(default_factory=dict)
    meta_groups: dict = field(default_factory=dict)
    activities: dict = field(default_factory=lambda: defaultdict(dict))
    products: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(dict)))
    materials: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(list)))
    probabilities: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(dict)))
    skills: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(list)))
    activity_names: dict = field(default_factory=dict)
    ship_volumes: dict = field(default_factory=dict)
    buildable_types: set = field(default_factory=set)
    inventable_by_product: dict = field(default_factory=dict)
    blueprint_names: dict = field(default_factory=dict)


def parse_sde(sde_dir: Path) -> SDEData:
    data = SDEData()

    for row in load_csv_bz2(sde_dir / 'invTypes.csv.bz2'):
        if int(row.get('published', 0)) != 1:
            continue
        tid = int(row['typeID'])
        data.types[tid] = {
            'typeID': tid,
            'groupID': int(row['groupID']),
            'typeName': row['typeName'],
            'volume': row.get('volume', '0'),
            'marketGroupID': int(row['marketGroupID']) if row.get('marketGroupID') and row['marketGroupID'] != 'None' else None,
            'mass': row.get('mass', '0'),
            'raceID': row.get('raceID'),
            'basePrice': row.get('basePrice'),
            'description': row.get('description', ''),
        }

    for row in load_csv_bz2(sde_dir / 'invGroups.csv.bz2'):
        if int(row.get('published', 0)) != 1:
            continue
        gid = int(row['groupID'])
        data.groups[gid] = {
            'groupID': gid,
            'categoryID': int(row['categoryID']),
            'groupName': row['groupName'],
            'iconID': row.get('iconID'),
        }

    for row in load_csv_bz2(sde_dir / 'invCategories.csv.bz2'):
        if int(row.get('published', 0)) != 1:
            continue
        cid = int(row['categoryID'])
        data.categories[cid] = {
            'categoryID': cid,
            'categoryName': row['categoryName'],
            'iconID': row.get('iconID'),
        }

    for row in load_csv_bz2(sde_dir / 'invMarketGroups.csv.bz2'):
        mg_id = int(row['marketGroupID'])
        parent_id = int(row['parentGroupID']) if row.get('parentGroupID') and row['parentGroupID'] != 'None' else None
        data.market_groups[mg_id] = {
            'marketGroupID': mg_id,
            'parentGroupID': parent_id,
            'marketGroupName': row['marketGroupName'],
            'description': row.get('description', ''),
            'iconID': row.get('iconID'),
            'hasTypes': int(row.get('hasTypes', 0)) == 1,
        }

    for row in load_csv_bz2(sde_dir / 'invMetaTypes.csv.bz2'):
        if row.get('metaGroupID'):
            data.meta_types[int(row['typeID'])] = int(row['metaGroupID'])

    for row in load_csv_bz2(sde_dir / 'invMetaGroups.csv.bz2'):
        data.meta_groups[int(row['metaGroupID'])] = row['metaGroupName']

    for row in load_csv_bz2(sde_dir / 'industryActivity.csv.bz2'):
        data.activities[int(row['typeID'])][int(row['activityID'])] = int(row['time'])

    for row in load_csv_bz2(sde_dir / 'industryActivityProducts.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        pid = int(row['productTypeID'])
        data.products[tid][aid][pid] = int(row['quantity'])

    for row in load_csv_bz2(sde_dir / 'industryActivityMaterials.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        data.materials[tid][aid].append({'typeID': int(row['materialTypeID']), 'quantity': int(row['quantity'])})

    for row in load_csv_bz2(sde_dir / 'industryActivityProbabilities.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        pid = int(row['productTypeID'])
        data.probabilities[tid][aid][pid] = float(row['probability'])

    for row in load_csv_bz2(sde_dir / 'industryActivitySkills.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        data.skills[tid][aid].append({'skillID': int(row['skillID']), 'level': int(row['level'])})

    for row in load_csv_bz2(sde_dir / 'ramActivities.csv.bz2'):
        if row.get('published') == '1':
            data.activity_names[int(row['activityID'])] = row['activityName']

    data.ship_volumes = {k: float(v) for k, v in load_yaml_file(sde_dir / 'ship_volumes.yaml').items()}

    for tid, acts in data.products.items():
        if 1 in acts or 8 in acts:
            data.buildable_types.add(tid)
        if 8 in acts:
            for pid in acts[8]:
                data.inventable_by_product[pid] = (tid, 8)

    for tid, tdata in data.types.items():
        if 'Blueprint' in tdata['typeName']:
            data.blueprint_names[tdata['typeName']] = tid

    return data


INVENTION = 8
MANUFACTURING = 1


def get_type_name(data: SDEData, tid: int) -> str:
    return data.types.get(tid, {}).get('typeName', '')


def get_group_path(data: SDEData, tid: int):
    tdata = data.types.get(tid)
    if not tdata:
        return 'Unknown', 'Unknown'
    gdata = data.groups.get(tdata['groupID'])
    if not gdata:
        return 'Unknown', 'Unknown'
    if cdata := data.categories.get(gdata['categoryID']):
        return cdata['categoryName'], gdata['groupName']
    return 'Unknown', gdata['groupName']


def get_market_group_path(data: SDEData, tid: int):
    tdata = data.types.get(tid)
    if not tdata or not tdata.get('marketGroupID'):
        return None
    path_parts = []
    mg_id = tdata['marketGroupID']
    while mg_id is not None:
        mgdata = data.market_groups.get(mg_id)
        if not mgdata:
            break
        path_parts.append(mgdata['marketGroupName'])
        mg_id = mgdata.get('parentGroupID')
    return ' > '.join(reversed(path_parts)) if path_parts else None


def get_tech_level(data: SDEData, tid: int) -> str:
    meta_id = data.meta_types.get(tid)
    if not meta_id:
        return 'Tech I'
    meta_name = data.meta_groups.get(meta_id, '')
    return meta_name if meta_name in ('Tech II', 'Tech III') else 'Tech I'


def get_volume(data: SDEData, tid: int) -> float:
    tdata = data.types.get(tid)
    if not tdata:
        return 0.0
    _, gname = get_group_path(data, tid)
    if gname in data.ship_volumes:
        return data.ship_volumes[gname]
    try:
        return float(tdata.get('volume') or '0')
    except ValueError:
        return 0.0


def get_invention_data(data: SDEData, pid: int, skill_level: int) -> Optional[dict]:
    bid, _ = data.inventable_by_product.get(pid, (None, None))
    if not bid:
        return None

    time_minutes = math.ceil(data.activities.get(bid, {}).get(INVENTION, 0) / 60)

    dc_materials = data.materials.get(bid, {}).get(INVENTION, [])
    datacores = []
    for mat in dc_materials:
        mname = get_type_name(data, mat['typeID'])
        if mname and mname.startswith('Datacore - '):
            datacores.append({'typeID': mat['typeID'], 'name': mname, 'quantity': mat['quantity']})

    skill_list = data.skills.get(bid, {}).get(INVENTION, [])
    skills = [{'name': get_type_name(data, s['skillID']), 'required_level': s['level']} for s in skill_list]

    base_prob = data.probabilities.get(bid, {}).get(INVENTION, {}).get(pid, 0.0)

    return {
        'invention_blueprint_id': bid,
        'time_minutes': time_minutes,
        'datacores': datacores,
        'skills': skills,
        'base_probability': base_prob,
        'tech_level': get_tech_level(data, pid)
    }


def get_recipe(data: SDEData, tid: int, me: int = 0) -> Optional[dict]:
    acts = data.products.get(tid, {})
    if MANUFACTURING not in acts:
        return None

    time_raw = data.activities.get(tid, {}).get(MANUFACTURING, 0)
    materials = data.materials.get(tid, {}).get(MANUFACTURING, [])

    if me > 0:
        materials = [{'typeID': m['typeID'], 'quantity': math.ceil(max(1, m['quantity'] * (1 - me / 100))), 'original_quantity': m['quantity']} for m in materials]
    else:
        materials = [{'typeID': m['typeID'], 'quantity': m['quantity'], 'original_quantity': m['quantity']} for m in materials]

    return {
        'activity': data.activity_names.get(MANUFACTURING, 'Manufacturing'),
        'output_qty': sum(acts[MANUFACTURING].values()),
        'run_time': round(time_raw / 60),
        'materials': materials
    }


def find_product_by_name(data: SDEData, name: str, bp_lookup: bool = True):
    for tid, tdata in data.types.items():
        if tdata['typeName'] == name:
            return tdata, tid, False
    if bp_lookup:
        for bp_name, bid in data.blueprint_names.items():
            if bp_name == name:
                return data.types.get(bid), bid, True
    return None, None, False


def calculate_probability(base_prob: float, skill_level: int, decryptor: str) -> float:
    mult = base_prob * (1 + 7 * skill_level / 120)
    dec = DECRYPTORS.get(decryptor, (0, 0, 0, 0))
    return max(0.0, min(1.0, mult * (1 + dec[0] / 100.0)))


DECRYPTORS = {
    'None': (0, 0, 0, 0),
    'Accelerant Decryptor': (20, 1, 2, 10),
    'Attainment Decryptor': (80, 4, -1, 4),
    'Augmentation Decryptor': (-40, 9, -2, 2),
    'Optimized Attainment Decryptor': (90, 2, 1, -2),
    'Optimized Augmentation Decryptor': (-10, 7, 2, 0),
    'Parity Decryptor': (50, 3, 1, -2),
    'Process Decryptor': (10, 0, 3, 6),
    'Symmetry Decryptor': (0, 2, 1, 8),
}

TECHIII_RELICS = {'Intact': 0.26, 'Malfunctioning': 0.21, 'Wrecked': 0.14}
TECHIII_BASE_RUNS = {'Intact': 20, 'Malfunctioning': 10, 'Wrecked': 3}


def parse_build_string(build_str: str) -> BuildParams:
    parts = build_str.strip().split()
    if len(parts) < 2:
        raise ValueError(f"Invalid build string format: {build_str}")

    num_jobs = 1
    x_idx = next((i for i, p in enumerate(parts) if p.lower().startswith('x')), -1)
    if x_idx >= 0:
        num_jobs = int(parts[x_idx][1:])
        parts = parts[:x_idx] + parts[x_idx+1:]

    # Find first numeric token
    first_num = next((i for i, p in enumerate(parts) if p.isdigit()), -1)
    if first_num <= 0:
        raise ValueError(f"Invalid build string format: {build_str}")

    item_name = ' '.join(parts[:first_num])
    tokens = parts[first_num:]

    if len(tokens) == 1:
        return BuildParams(item_name, int(tokens[0]), num_jobs)
    if len(tokens) == 2:
        try:
            return BuildParams(item_name, int(tokens[0]), num_jobs, me=int(tokens[1]))
        except ValueError:
            return BuildParams(item_name, int(tokens[0]), num_jobs, decryptor=tokens[1], build_type='invention')
    if len(tokens) == 3:
        return BuildParams(item_name, int(tokens[0]), num_jobs, me=int(tokens[1]), te=int(tokens[2]))
    if len(tokens) == 4:
        return BuildParams(item_name, int(tokens[0]), num_jobs, decryptor=tokens[1], relic=tokens[2], build_type='re')

    raise ValueError(f"Invalid build string format. Unexpected argument count: {build_str}")


def generate_invention_report(data: SDEData, name: str, skill: int) -> str:
    tdata, tid, is_bp = find_product_by_name(data, name)
    if not tdata:
        return f"Error: Item '{name}' not found or not published.\n"

    if is_bp:
        inv = data.products.get(tid, {}).get(INVENTION, {})
        if inv:
            tid = next(iter(inv.keys()))
            tdata = data.types.get(tid)
        else:
            return f"Error: '{name}' is not an inventable blueprint.\n"

    inv = get_invention_data(data, tid, skill)
    if not inv:
        return f"Error: '{name}' is not an inventable item.\n"

    tech = inv['tech_level']
    if tech not in ('Tech II', 'Tech III'):
        return f"Error: '{name}' is not Tech II or Tech III.\n"

    cat, grp = get_group_path(data, tid)
    mg = get_market_group_path(data, tid)

    lines = [
        f"ITEM: {tdata['typeName']} ({tid})",
        f"Group: {cat} > {grp}",
        f"Market Group: {mg if mg else 'None'}",
        f"Tech Level: {tech}",
        "",
        "Invention:",
    ]

    if tech == 'Tech II':
        lines.append(f"Base: {get_type_name(data, inv['invention_blueprint_id'])} ({inv['invention_blueprint_id']})")

    dc = sorted(inv['datacores'], key=lambda d: d['name'].lower())
    lines.append(f"Datacores: {', '.join(d['name'] for d in dc)}")
    lines.append(f"Required Per Run: {dc[0]['quantity'] if dc else 0}")

    sk = sorted(inv['skills'], key=lambda s: s['name'].lower())
    lines.append(f"Skills: {', '.join(s['name'] for s in sk)}")
    lines.append(f"Time: {inv['time_minutes']}")

    if tech == 'Tech II':
        base_bp = inv['invention_blueprint_id']
        base_runs = data.products.get(base_bp, {}).get(INVENTION, {}).get(tid, 10)
        lines.extend(["Probabilities:", "| Decryptor                       | Probability | Runs | ME | TE |", "|---------------------------------|-------------|------|----|----|"])
        for dname in sorted(DECRYPTORS.keys(), key=str.lower):
            prob = calculate_probability(inv['base_probability'], skill, dname)
            _, dr, dme, dte = DECRYPTORS[dname]
            lines.append(f"| {dname:<31} | {prob:>9.2f} | {base_runs + dr:>4} | {2 + dme:>2} | {4 + dte:>2} |")
    else:
        lines.extend(["Probabilities:", "| Invented From                | Decryptor                       | Probability | Runs | ME | TE |", "|------------------------------|---------------------------------|-------------|------|----|----|"])
        for rel in ('Intact', 'Malfunctioning', 'Wrecked'):
            for dname in sorted(DECRYPTORS.keys(), key=str.lower):
                prob = calculate_probability(TECHIII_RELICS[rel], skill, dname)
                _, dr, dme, dte = DECRYPTORS[dname]
                lines.append(f"| {rel:<28} | {dname:<31} | {prob:>9.2f} | {TECHIII_BASE_RUNS[rel] + dr:>4} | {2 + dme:>2} | {4 + dte:>2} |")

    return '\n'.join(lines) + '\n'


def write_jobs_csv(path: Path, name: str, runs: int, days: float, count: int):
    with open(path, 'w', newline='', encoding='utf-8') as f:
        w = csv.writer(f)
        w.writerow(['name', 'runs', 'days', 'count'])
        w.writerow([name, runs, days, count])


def write_materials_csv(path: Path, mat_data: dict):
    with open(path, 'w', newline='', encoding='utf-8') as f:
        w = csv.writer(f)
        w.writerow(['name', 'to_buy', 'buy_volume', 'start_amount', 'end_amount'])
        for name in sorted(mat_data.keys()):
            qty = mat_data[name]
            w.writerow([name, qty, round(qty / 10, 1), 0, 0])


def resolve_blueprint_product(data: SDEData, bid: int):
    for pid, acts in data.products.items():
        if pid == bid:
            for act in acts.values():
                if act:
                    product_id = next(iter(act.keys()))
                    return product_id, data.types.get(product_id)
    return None, None


def generate_plan(data: SDEData, params: BuildParams, config: dict, out_dir: Path) -> str:
    out_dir.mkdir(parents=True, exist_ok=True)

    tdata, tid, found_bp = find_product_by_name(data, params.item_name)
    if not tdata:
        return f"Error: Item '{params.item_name}' not found or not published.\n"

    bid = tid if found_bp else None
    if bid:
        tid, tdata = resolve_blueprint_product(data, bid)
        if not tid:
            return f"Error: No product found for blueprint.\n"

    if params.build_type in ('invention', 're'):
        return _gen_invention_plan(data, params, config, out_dir, tid, bid)
    return _gen_manufacturing_plan(data, params, config, out_dir, tid, bid)


def _gen_invention_plan(data: SDEData, params: BuildParams, config: dict, out_dir: Path, tid: int, bid: int):
    inv = get_invention_data(data, tid, config.get('invention_skill', 3))
    if not inv:
        return f"Error: item not inventable.\n"

    prob = calculate_probability(inv['base_probability'], config.get('invention_skill', 3), params.decryptor)
    _, dr, _, _ = DECRYPTORS.get(params.decryptor, (0, 0, 0, 0))

    rel = params.relic or 'Malfunctioning'
    base_runs = TECHIII_BASE_RUNS.get(rel, 10) if params.build_type == 're' else data.products.get(inv['invention_blueprint_id'], {}).get(INVENTION, {}).get(tid, 10)
    runs = base_runs + dr

    total_runs = params.num_jobs * params.runs_per_job
    exp_bp_runs = math.ceil(total_runs / (runs * prob))

    dc_materials = data.materials.get(inv['invention_blueprint_id'], {}).get(INVENTION, [])
    dc_data = {}
    for mat in dc_materials:
        mname = get_type_name(data, mat['typeID'])
        if mname and mname.startswith('Datacore - '):
            dc_data[mname] = dc_data.get(mname, 0) + mat['quantity'] * exp_bp_runs

    write_materials_csv(out_dir / 'materials.csv', dc_data)

    invent_time = inv['time_minutes'] * exp_bp_runs
    bp_name = get_type_name(data, inv['invention_blueprint_id']) or f"Blueprint {inv['invention_blueprint_id']}"
    write_jobs_csv(out_dir / 'jobs.csv', f"{bp_name} Blueprints", exp_bp_runs, math.ceil(invent_time / 60 / 24 * 100) / 100, 1)

    return f"Plan generated: {out_dir / 'materials.csv'}, {out_dir / 'jobs.csv'}\n"


def _gen_manufacturing_plan(data: SDEData, params: BuildParams, config: dict, out_dir: Path, tid: int, bid: int):
    # Find blueprint if not provided
    if not bid:
        for pid, acts in data.products.items():
            if MANUFACTURING in acts and tid in acts[MANUFACTURING]:
                bid = pid
                break
        if not bid:
            return f"Error: No manufacturing blueprint found.\n"

    bp_time = data.activities.get(bid, {}).get(MANUFACTURING, 0)
    if bp_time == 0:
        bp_time = data.activities.get(tid, {}).get(MANUFACTURING, 0)

    te_bonus = config.get('te_bonus', 20)
    full_te = bp_time * (1 - params.te / 100) * (1 - te_bonus / 100)
    run_days = full_te / 60 / 24

    materials = [{'typeID': m['typeID'], 'quantity': math.ceil(max(1, m['quantity'] * (1 - params.me / 100))), 'original_quantity': m['quantity']} for m in data.materials.get(bid, {}).get(MANUFACTURING, [])]

    total_runs = params.num_jobs * params.runs_per_job
    mat_total = {}
    for mat in materials:
        name = get_type_name(data, mat['typeID']) or f'Type {mat["typeID"]}'
        mat_total[name] = mat_total.get(name, 0) + mat['quantity'] * total_runs

    write_materials_csv(out_dir / 'materials.csv', mat_total)

    bp_name = get_type_name(data, bid) or f"Blueprint {bid}"
    with open(out_dir / 'jobs.csv', 'w', newline='', encoding='utf-8') as f:
        w = csv.writer(f)
        w.writerow(['name', 'runs', 'days', 'count'])
        for j in range(1, params.num_jobs + 1):
            w.writerow([bp_name, params.runs_per_job, round(run_days * params.runs_per_job, 2), j])

    return f"Plan generated: {out_dir / 'materials.csv'}, {out_dir / 'jobs.csv'}\n"


def generate_report(data: SDEData, name: str, me: int = 0, te: int = 0, waste: bool = False) -> str:
    tdata, tid, found_bp = find_product_by_name(data, name)
    if not tdata:
        return f"Error: Item '{name}' not found or not published.\n"

    bid = tid if found_bp else None
    disp_tid, disp_tdata = tid, tdata
    if bid:
        disp_tid, disp_tdata = resolve_blueprint_product(data, bid) or (tid, tdata)

    recipe = get_recipe(data, disp_tid, me)
    if not recipe:
        return f"Error: No industry activity found for '{name}'.\n"

    cat, grp = get_group_path(data, disp_tid)
    mg = get_market_group_path(data, disp_tid)
    tech = get_tech_level(data, disp_tid)
    vol = get_volume(data, disp_tid)

    run_time = round(recipe['run_time'] * (1 - te / 100)) if te > 0 else recipe['run_time']

    def mat_row(m):
        mname = get_type_name(data, m['typeID']) or 'Unknown'
        buildable = 'Yes' if any(a in data.buildable_types for a in [m['typeID']]) else 'No'
        if waste:
            return f"| {mname} | {m['quantity']} | {m['original_quantity'] - m['quantity']} | {buildable} |"
        return f"| {mname} | {m['quantity']} | {buildable} |"

    header = "| Item | Quantity | Waste | Buildable |" if waste else "| Item | Quantity | Buildable |"
    sep = "|:-:|:-:|:-:|---:|" if waste else "|:-:|:---:|---:|"

    lines = [
        f"ITEM: {disp_tdata['typeName']} ({disp_tid})",
        f"Group: {cat} > {grp}",
        f"Market Group: {mg if mg else 'None'}",
        f"Tech Level: {tech}",
        f"Volume: {vol:.2f}",
        "",
        "Recipe:",
        f"Activity: {recipe['activity']}",
        f"Output Quantity: {recipe['output_qty']}",
        f"Run Time: {run_time}",
        header,
        sep,
    ]
    for mat in sorted(recipe['materials'], key=lambda m: (get_type_name(data, m['typeID']) or '').lower()):
        lines.append(mat_row(mat))

    return '\n'.join(lines) + '\n'


def main():
    p = argparse.ArgumentParser(description='EVE Online Industrial Planner')
    s = p.add_subparsers(dest='command')

    r = s.add_parser('recipe', help='Generate recipe report')
    r.add_argument('target')
    r.add_argument('--sde', required=True)
    r.add_argument('--me', type=int, default=0)
    r.add_argument('--te', type=int, default=0)
    r.add_argument('--waste', action='store_true')

    inv = s.add_parser('invention', help='Generate invention report')
    inv.add_argument('target')
    inv.add_argument('--sde', required=True)
    inv.add_argument('--skill', type=int, choices=range(1, 6), default=5)

    pl = s.add_parser('plan', help='Create build plan')
    pl.add_argument('build_string')
    pl.add_argument('--config', required=True)
    pl.add_argument('--sde', required=True)
    pl.add_argument('--output', required=True)

    args = p.parse_args()
    if not args.command:
        p.print_help()
        sys.exit(1)

    sde_path = Path(args.sde)
    if not sde_path.exists():
        print(f"Error: SDE '{args.sde}' not found.", file=sys.stderr)
        sys.exit(1)

    d = parse_sde(sde_path)

    if args.command == 'recipe':
        if not 0 <= args.me <= 10:
            print(f"Error: ME must be 0-10, got {args.me}", file=sys.stderr)
            sys.exit(1)
        if not 0 <= args.te <= 20 or args.te % 2 != 0:
            print(f"Error: TE must be even 0-20, got {args.te}", file=sys.stderr)
            sys.exit(1)
        print(generate_report(d, args.target, args.me, args.te, args.waste), end='')
    elif args.command == 'invention':
        print(generate_invention_report(d, args.target, args.skill), end='')
    elif args.command == 'plan':
        try:
            params = parse_build_string(args.build_string)
        except ValueError as e:
            print(f"Error: {e}", file=sys.stderr)
            sys.exit(1)
        cfg = load_yaml_file(Path(args.config))
        print(generate_plan(d, params, cfg, Path(args.output)), end='')


if __name__ == '__main__':
    main()

#!/usr/bin/env python3
"""EVE Online Industrial Planner - Parse SDE and emit recipe reports."""

import argparse
import bz2
import csv
import math
import sys
from pathlib import Path
from collections import defaultdict
from dataclasses import dataclass
from typing import Optional, field

import yaml


def load_csv_bz2(filepath: Path):
    with bz2.open(filepath, 'rt', encoding='utf-8') as f:
        return list(csv.DictReader(f))


def load_yaml_file(filepath: Path):
    with open(filepath, 'r', encoding='utf-8') as f:
        return yaml.safe_load(f)


@dataclass
class BuildParams:
    item_name: str
    runs_per_job: int
    num_jobs: int
    me: int = 0
    te: int = 0
    decryptor: str = 'None'
    relic: Optional[str] = None
    build_type: str = 'normal'


@dataclass
class SDEData:
    types: dict = field(default_factory=dict)
    groups: dict = field(default_factory=dict)
    categories: dict = field(default_factory=dict)
    market_groups: dict = field(default_factory=dict)
    meta_types: dict = field(default_factory=dict)
    meta_groups: dict = field(default_factory=dict)
    activities: dict = field(default_factory=lambda: defaultdict(dict))
    products: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(dict)))
    materials: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(list)))
    probabilities: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(dict)))
    skills: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(list)))
    activity_names: dict = field(default_factory=dict)
    ship_volumes: dict = field(default_factory=dict)
    buildable_types: set = field(default_factory=set)
    inventable_by_product: dict = field(default_factory=dict)
    blueprint_names: dict = field(default_factory=dict)


def parse_sde(sde_dir: Path) -> SDEData:
    data = SDEData()

    for row in load_csv_bz2(sde_dir / 'invTypes.csv.bz2'):
        if int(row.get('published', 0)) != 1:
            continue
        tid = int(row['typeID'])
        data.types[tid] = {
            'typeID': tid,
            'groupID': int(row['groupID']),
            'typeName': row['typeName'],
            'volume': row.get('volume', '0'),
            'marketGroupID': int(row['marketGroupID']) if row.get('marketGroupID') and row['marketGroupID'] != 'None' else None,
            'mass': row.get('mass', '0'),
            'raceID': row.get('raceID'),
            'basePrice': row.get('basePrice'),
            'description': row.get('description', ''),
        }

    for row in load_csv_bz2(sde_dir / 'invGroups.csv.bz2'):
        if int(row.get('published', 0)) != 1:
            continue
        gid = int(row['groupID'])
        data.groups[gid] = {
            'groupID': gid,
            'categoryID': int(row['categoryID']),
            'groupName': row['groupName'],
            'iconID': row.get('iconID'),
        }

    for row in load_csv_bz2(sde_dir / 'invCategories.csv.bz2'):
        if int(row.get('published', 0)) != 1:
            continue
        cid = int(row['categoryID'])
        data.categories[cid] = {
            'categoryID': cid,
            'categoryName': row['categoryName'],
            'iconID': row.get('iconID'),
        }

    for row in load_csv_bz2(sde_dir / 'invMarketGroups.csv.bz2'):
        mg_id = int(row['marketGroupID'])
        parent_id = int(row['parentGroupID']) if row.get('parentGroupID') and row['parentGroupID'] != 'None' else None
        data.market_groups[mg_id] = {
            'marketGroupID': mg_id,
            'parentGroupID': parent_id,
            'marketGroupName': row['marketGroupName'],
            'description': row.get('description', ''),
            'iconID': row.get('iconID'),
            'hasTypes': int(row.get('hasTypes', 0)) == 1,
        }

    for row in load_csv_bz2(sde_dir / 'invMetaTypes.csv.bz2'):
        if row.get('metaGroupID'):
            data.meta_types[int(row['typeID'])] = int(row['metaGroupID'])

    for row in load_csv_bz2(sde_dir / 'invMetaGroups.csv.bz2'):
        data.meta_groups[int(row['metaGroupID'])] = row['metaGroupName']

    for row in load_csv_bz2(sde_dir / 'industryActivity.csv.bz2'):
        data.activities[int(row['typeID'])][int(row['activityID'])] = int(row['time'])

    for row in load_csv_bz2(sde_dir / 'industryActivityProducts.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        pid = int(row['productTypeID'])
        data.products[tid][aid][pid] = int(row['quantity'])

    for row in load_csv_bz2(sde_dir / 'industryActivityMaterials.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        data.materials[tid][aid].append({'typeID': int(row['materialTypeID']), 'quantity': int(row['quantity'])})

    for row in load_csv_bz2(sde_dir / 'industryActivityProbabilities.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        pid = int(row['productTypeID'])
        data.probabilities[tid][aid][pid] = float(row['probability'])

    for row in load_csv_bz2(sde_dir / 'industryActivitySkills.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        data.skills[tid][aid].append({'skillID': int(row['skillID']), 'level': int(row['level'])})

    for row in load_csv_bz2(sde_dir / 'ramActivities.csv.bz2'):
        if row.get('published') == '1':
            data.activity_names[int(row['activityID'])] = row['activityName']

    data.ship_volumes = {k: float(v) for k, v in load_yaml_file(sde_dir / 'ship_volumes.yaml').items()}

    for tid, acts in data.products.items():
        if 1 in acts or 8 in acts:
            data.buildable_types.add(tid)
        if 8 in acts:
            for pid in acts[8]:
                data.inventable_by_product[pid] = (tid, 8)

    for tid, tdata in data.types.items():
        if 'Blueprint' in tdata['typeName']:
            data.blueprint_names[tdata['typeName']] = tid

    return data


INVENTION = 8
MANUFACTURING = 1


def get_type_name(data: SDEData, tid: int) -> str:
    return data.types.get(tid, {}).get('typeName', '')


def get_group_path(data: SDEData, tid: int):
    tdata = data.types.get(tid)
    if not tdata:
        return 'Unknown', 'Unknown'
    gdata = data.groups.get(tdata['groupID'])
    if not gdata:
        return 'Unknown', 'Unknown'
    if cdata := data.categories.get(gdata['categoryID']):
        return cdata['categoryName'], gdata['groupName']
    return 'Unknown', gdata['groupName']


def get_market_group_path(data: SDEData, tid: int):
    tdata = data.types.get(tid)
    if not tdata or not tdata.get('marketGroupID'):
        return None
    path_parts = []
    mg_id = tdata['marketGroupID']
    while mg_id is not None:
        mgdata = data.market_groups.get(mg_id)
        if not mgdata:
            break
        path_parts.append(mgdata['marketGroupName'])
        mg_id = mgdata.get('parentGroupID')
    return ' > '.join(reversed(path_parts)) if path_parts else None


def get_tech_level(data: SDEData, tid: int) -> str:
    meta_id = data.meta_types.get(tid)
    if not meta_id:
        return 'Tech I'
    meta_name = data.meta_groups.get(meta_id, '')
    return meta_name if meta_name in ('Tech II', 'Tech III') else 'Tech I'


def get_volume(data: SDEData, tid: int) -> float:
    tdata = data.types.get(tid)
    if not tdata:
        return 0.0
    _, gname = get_group_path(data, tid)
    if gname in data.ship_volumes:
        return data.ship_volumes[gname]
    try:
        return float(tdata.get('volume') or '0')
    except ValueError:
        return 0.0


def get_invention_data(data: SDEData, pid: int, skill_level: int) -> Optional[dict]:
    bid, _ = data.inventable_by_product.get(pid, (None, None))
    if not bid:
        return None

    time_minutes = math.ceil(data.activities.get(bid, {}).get(INVENTION, 0) / 60)

    dc_materials = data.materials.get(bid, {}).get(INVENTION, [])
    datacores = []
    for mat in dc_materials:
        mname = get_type_name(data, mat['typeID'])
        if mname and mname.startswith('Datacore - '):
            datacores.append({'typeID': mat['typeID'], 'name': mname, 'quantity': mat['quantity']})

    skill_list = data.skills.get(bid, {}).get(INVENTION, [])
    skills = [{'name': get_type_name(data, s['skillID']), 'required_level': s['level']} for s in skill_list]

    base_prob = data.probabilities.get(bid, {}).get(INVENTION, {}).get(pid, 0.0)

    return {
        'invention_blueprint_id': bid,
        'time_minutes': time_minutes,
        'datacores': datacores,
        'skills': skills,
        'base_probability': base_prob,
        'tech_level': get_tech_level(data, pid)
    }


def get_recipe(data: SDEData, tid: int, me: int = 0) -> Optional[dict]:
    acts = data.products.get(tid, {})
    if MANUFACTURING not in acts:
        return None

    time_raw = data.activities.get(tid, {}).get(MANUFACTURING, 0)
    materials = data.materials.get(tid, {}).get(MANUFACTURING, [])

    if me > 0:
        materials = [{'typeID': m['typeID'], 'quantity': math.ceil(max(1, m['quantity'] * (1 - me / 100))), 'original_quantity': m['quantity']} for m in materials]
    else:
        materials = [{'typeID': m['typeID'], 'quantity': m['quantity'], 'original_quantity': m['quantity']} for m in materials]

    return {
        'activity': data.activity_names.get(MANUFACTURING, 'Manufacturing'),
        'output_qty': sum(acts[MANUFACTURING].values()),
        'run_time': round(time_raw / 60),
        'materials': materials
    }


def find_product_by_name(data: SDEData, name: str, bp_lookup: bool = True):
    for tid, tdata in data.types.items():
        if tdata['typeName'] == name:
            return tdata, tid, False
    if bp_lookup:
        for bp_name, bid in data.blueprint_names.items():
            if bp_name == name:
                return data.types.get(bid), bid, True
    return None, None, False


def calculate_probability(base_prob: float, skill_level: int, decryptor: str) -> float:
    mult = base_prob * (1 + 7 * skill_level / 120)
    dec = DECRYPTORS.get(decryptor, (0, 0, 0, 0))
    return max(0.0, min(1.0, mult * (1 + dec[0] / 100.0)))


DECRYPTORS = {
    'None': (0, 0, 0, 0),
    'Accelerant Decryptor': (20, 1, 2, 10),
    'Attainment Decryptor': (80, 4, -1, 4),
    'Augmentation Decryptor': (-40, 9, -2, 2),
    'Optimized Attainment Decryptor': (90, 2, 1, -2),
    'Optimized Augmentation Decryptor': (-10, 7, 2, 0),
    'Parity Decryptor': (50, 3, 1, -2),
    'Process Decryptor': (10, 0, 3, 6),
    'Symmetry Decryptor': (0, 2, 1, 8),
}

TECHIII_RELICS = {'Intact': 0.26, 'Malfunctioning': 0.21, 'Wrecked': 0.14}
TECHIII_BASE_RUNS = {'Intact': 20, 'Malfunctioning': 10, 'Wrecked': 3}


def parse_build_string(build_str: str) -> BuildParams:
    parts = build_str.strip().split()
    if len(parts) < 2:
        raise ValueError(f"Invalid build string format: {build_str}")

    num_jobs = 1
    x_idx = next((i for i, p in enumerate(parts) if p.lower().startswith('x')), -1)
    if x_idx >= 0:
        num_jobs = int(parts[x_idx][1:])
        parts = parts[:x_idx] + parts[x_idx+1:]

    # Find first numeric token
    first_num = next((i for i, p in enumerate(parts) if p.isdigit()), -1)
    if first_num <= 0:
        raise ValueError(f"Invalid build string format: {build_str}")

    item_name = ' '.join(parts[:first_num])
    tokens = parts[first_num:]

    if len(tokens) == 1:
        return BuildParams(item_name, int(tokens[0]), num_jobs)
    if len(tokens) == 2:
        try:
            return BuildParams(item_name, int(tokens[0]), num_jobs, me=int(tokens[1]))
        except ValueError:
            return BuildParams(item_name, int(tokens[0]), num_jobs, decryptor=tokens[1], build_type='invention')
    if len(tokens) == 3:
        return BuildParams(item_name, int(tokens[0]), num_jobs, me=int(tokens[1]), te=int(tokens[2]))
    if len(tokens) == 4:
        return BuildParams(item_name, int(tokens[0]), num_jobs, decryptor=tokens[1], relic=tokens[2], build_type='re')

    raise ValueError(f"Invalid build string format. Unexpected argument count: {build_str}")


def generate_invention_report(data: SDEData, name: str, skill: int) -> str:
    tdata, tid, is_bp = find_product_by_name(data, name)
    if not tdata:
        return f"Error: Item '{name}' not found or not published.\n"

    if is_bp:
        inv = data.products.get(tid, {}).get(INVENTION, {})
        if inv:
            tid = next(iter(inv.keys()))
            tdata = data.types.get(tid)
        else:
            return f"Error: '{name}' is not an inventable blueprint.\n"

    inv = get_invention_data(data, tid, skill)
    if not inv:
        return f"Error: '{name}' is not an inventable item.\n"

    tech = inv['tech_level']
    if tech not in ('Tech II', 'Tech III'):
        return f"Error: '{name}' is not Tech II or Tech III.\n"

    cat, grp = get_group_path(data, tid)
    mg = get_market_group_path(data, tid)

    lines = [
        f"ITEM: {tdata['typeName']} ({tid})",
        f"Group: {cat} > {grp}",
        f"Market Group: {mg if mg else 'None'}",
        f"Tech Level: {tech}",
        "",
        "Invention:",
    ]

    if tech == 'Tech II':
        lines.append(f"Base: {get_type_name(data, inv['invention_blueprint_id'])} ({inv['invention_blueprint_id']})")

    dc = sorted(inv['datacores'], key=lambda d: d['name'].lower())
    lines.append(f"Datacores: {', '.join(d['name'] for d in dc)}")
    lines.append(f"Required Per Run: {dc[0]['quantity'] if dc else 0}")

    sk = sorted(inv['skills'], key=lambda s: s['name'].lower())
    lines.append(f"Skills: {', '.join(s['name'] for s in sk)}")
    lines.append(f"Time: {inv['time_minutes']}")

    if tech == 'Tech II':
        base_bp = inv['invention_blueprint_id']
        base_runs = data.products.get(base_bp, {}).get(INVENTION, {}).get(tid, 10)
        lines.extend(["Probabilities:", "| Decryptor                       | Probability | Runs | ME | TE |", "|---------------------------------|-------------|------|----|----|"])
        for dname in sorted(DECRYPTORS.keys(), key=str.lower):
            prob = calculate_probability(inv['base_probability'], skill, dname)
            _, dr, dme, dte = DECRYPTORS[dname]
            lines.append(f"| {dname:<31} | {prob:>9.2f} | {base_runs + dr:>4} | {2 + dme:>2} | {4 + dte:>2} |")
    else:
        lines.extend(["Probabilities:", "| Invented From                | Decryptor                       | Probability | Runs | ME | TE |", "|------------------------------|---------------------------------|-------------|------|----|----|"])
        for rel in ('Intact', 'Malfunctioning', 'Wrecked'):
            for dname in sorted(DECRYPTORS.keys(), key=str.lower):
                prob = calculate_probability(TECHIII_RELICS[rel], skill, dname)
                _, dr, dme, dte = DECRYPTORS[dname]
                lines.append(f"| {rel:<28} | {dname:<31} | {prob:>9.2f} | {TECHIII_BASE_RUNS[rel] + dr:>4} | {2 + dme:>2} | {4 + dte:>2} |")

    return '\n'.join(lines) + '\n'


def write_jobs_csv(path: Path, name: str, runs: int, days: float, count: int):
    with open(path, 'w', newline='', encoding='utf-8') as f:
        w = csv.writer(f)
        w.writerow(['name', 'runs', 'days', 'count'])
        w.writerow([name, runs, days, count])


def write_materials_csv(path: Path, mat_data: dict):
    with open(path, 'w', newline='', encoding='utf-8') as f:
        w = csv.writer(f)
        w.writerow(['name', 'to_buy', 'buy_volume', 'start_amount', 'end_amount'])
        for name in sorted(mat_data.keys()):
            qty = mat_data[name]
            w.writerow([name, qty, round(qty / 10, 1), 0, 0])


def resolve_blueprint_product(data: SDEData, bid: int):
    for pid, acts in data.products.items():
        if pid == bid:
            for act in acts.values():
                if act:
                    product_id = next(iter(act.keys()))
                    return product_id, data.types.get(product_id)
    return None, None


def generate_plan(data: SDEData, params: BuildParams, config: dict, out_dir: Path) -> str:
    out_dir.mkdir(parents=True, exist_ok=True)

    tdata, tid, found_bp = find_product_by_name(data, params.item_name)
    if not tdata:
        return f"Error: Item '{params.item_name}' not found or not published.\n"

    bid = tid if found_bp else None
    if bid:
        tid, tdata = resolve_blueprint_product(data, bid)
        if not tid:
            return f"Error: No product found for blueprint.\n"

    if params.build_type in ('invention', 're'):
        return _gen_invention_plan(data, params, config, out_dir, tid, bid)
    return _gen_manufacturing_plan(data, params, config, out_dir, tid, bid)


def _gen_invention_plan(data: SDEData, params: BuildParams, config: dict, out_dir: Path, tid: int, bid: int):
    inv = get_invention_data(data, tid, config.get('invention_skill', 3))
    if not inv:
        return f"Error: item not inventable.\n"

    prob = calculate_probability(inv['base_probability'], config.get('invention_skill', 3), params.decryptor)
    _, dr, _, _ = DECRYPTORS.get(params.decryptor, (0, 0, 0, 0))

    rel = params.relic or 'Malfunctioning'
    base_runs = TECHIII_BASE_RUNS.get(rel, 10) if params.build_type == 're' else data.products.get(inv['invention_blueprint_id'], {}).get(INVENTION, {}).get(tid, 10)
    runs = base_runs + dr

    total_runs = params.num_jobs * params.runs_per_job
    exp_bp_runs = math.ceil(total_runs / (runs * prob))

    dc_materials = data.materials.get(inv['invention_blueprint_id'], {}).get(INVENTION, [])
    dc_data = {}
    for mat in dc_materials:
        mname = get_type_name(data, mat['typeID'])
        if mname and mname.startswith('Datacore - '):
            dc_data[mname] = dc_data.get(mname, 0) + mat['quantity'] * exp_bp_runs

    write_materials_csv(out_dir / 'materials.csv', dc_data)

    invent_time = inv['time_minutes'] * exp_bp_runs
    bp_name = get_type_name(data, inv['invention_blueprint_id']) or f"Blueprint {inv['invention_blueprint_id']}"
    write_jobs_csv(out_dir / 'jobs.csv', f"{bp_name} Blueprints", exp_bp_runs, math.ceil(invent_time / 60 / 24 * 100) / 100, 1)

    return f"Plan generated: {out_dir / 'materials.csv'}, {out_dir / 'jobs.csv'}\n"


def _gen_manufacturing_plan(data: SDEData, params: BuildParams, config: dict, out_dir: Path, tid: int, bid: int):
    # Find blueprint if not provided
    if not bid:
        for pid, acts in data.products.items():
            if MANUFACTURING in acts and tid in acts[MANUFACTURING]:
                bid = pid
                break
        if not bid:
            return f"Error: No manufacturing blueprint found.\n"

    bp_time = data.activities.get(bid, {}).get(MANUFACTURING, 0)
    if bp_time == 0:
        bp_time = data.activities.get(tid, {}).get(MANUFACTURING, 0)

    te_bonus = config.get('te_bonus', 20)
    full_te = bp_time * (1 - params.te / 100) * (1 - te_bonus / 100)
    run_days = full_te / 60 / 24

    materials = [{'typeID': m['typeID'], 'quantity': math.ceil(max(1, m['quantity'] * (1 - params.me / 100))), 'original_quantity': m['quantity']} for m in data.materials.get(bid, {}).get(MANUFACTURING, [])]

    total_runs = params.num_jobs * params.runs_per_job
    mat_total = {}
    for mat in materials:
        name = get_type_name(data, mat['typeID']) or f'Type {mat["typeID"]}'
        mat_total[name] = mat_total.get(name, 0) + mat['quantity'] * total_runs

    write_materials_csv(out_dir / 'materials.csv', mat_total)

    bp_name = get_type_name(data, bid) or f"Blueprint {bid}"
    with open(out_dir / 'jobs.csv', 'w', newline='', encoding='utf-8') as f:
        w = csv.writer(f)
        w.writerow(['name', 'runs', 'days', 'count'])
        for j in range(1, params.num_jobs + 1):
            w.writerow([bp_name, params.runs_per_job, round(run_days * params.runs_per_job, 2), j])

    return f"Plan generated: {out_dir / 'materials.csv'}, {out_dir / 'jobs.csv'}\n"


def generate_report(data: SDEData, name: str, me: int = 0, te: int = 0, waste: bool = False) -> str:
    tdata, tid, found_bp = find_product_by_name(data, name)
    if not tdata:
        return f"Error: Item '{name}' not found or not published.\n"

    bid = tid if found_bp else None
    disp_tid, disp_tdata = tid, tdata
    if bid:
        disp_tid, disp_tdata = resolve_blueprint_product(data, bid) or (tid, tdata)

    recipe = get_recipe(data, disp_tid, me)
    if not recipe:
        return f"Error: No industry activity found for '{name}'.\n"

    cat, grp = get_group_path(data, disp_tid)
    mg = get_market_group_path(data, disp_tid)
    tech = get_tech_level(data, disp_tid)
    vol = get_volume(data, disp_tid)

    run_time = round(recipe['run_time'] * (1 - te / 100)) if te > 0 else recipe['run_time']

    def mat_row(m):
        mname = get_type_name(data, m['typeID']) or 'Unknown'
        buildable = 'Yes' if any(a in data.buildable_types for a in [m['typeID']]) else 'No'
        if waste:
            return f"| {mname} | {m['quantity']} | {m['original_quantity'] - m['quantity']} | {buildable} |"
        return f"| {mname} | {m['quantity']} | {buildable} |"

    header = "| Item | Quantity | Waste | Buildable |" if waste else "| Item | Quantity | Buildable |"
    sep = "|:-:|:-:|:-:|---:|" if waste else "|:-:|:---:|---:|"

    lines = [
        f"ITEM: {disp_tdata['typeName']} ({disp_tid})",
        f"Group: {cat} > {grp}",
        f"Market Group: {mg if mg else 'None'}",
        f"Tech Level: {tech}",
        f"Volume: {vol:.2f}",
        "",
        "Recipe:",
        f"Activity: {recipe['activity']}",
        f"Output Quantity: {recipe['output_qty']}",
        f"Run Time: {run_time}",
        header,
        sep,
    ]
    for mat in sorted(recipe['materials'], key=lambda m: (get_type_name(data, m['typeID']) or '').lower()):
        lines.append(mat_row(mat))

    return '\n'.join(lines) + '\n'


def main():
    p = argparse.ArgumentParser(description='EVE Online Industrial Planner')
    s = p.add_subparsers(dest='command')

    r = s.add_parser('recipe', help='Generate recipe report')
    r.add_argument('target')
    r.add_argument('--sde', required=True)
    r.add_argument('--me', type=int, default=0)
    r.add_argument('--te', type=int, default=0)
    r.add_argument('--waste', action='store_true')

    inv = s.add_parser('invention', help='Generate invention report')
    inv.add_argument('target')
    inv.add_argument('--sde', required=True)
    inv.add_argument('--skill', type=int, choices=range(1, 6), default=5)

    pl = s.add_parser('plan', help='Create build plan')
    pl.add_argument('build_string')
    pl.add_argument('--config', required=True)
    pl.add_argument('--sde', required=True)
    pl.add_argument('--output', required=True)
    pl.add_argument('--build-all', action='store_true', help='Build all components in the dependency tree')

    args = p.parse_args()
    if not args.command:
        p.print_help()
        sys.exit(1)

    sde_path = Path(args.sde)
    if not sde_path.exists():
        print(f"Error: SDE '{args.sde}' not found.", file=sys.stderr)
        sys.exit(1)

    d = parse_sde(sde_path)

    if args.command == 'recipe':
        if not 0 <= args.me <= 10:
            print(f"Error: ME must be 0-10, got {args.me}", file=sys.stderr)
            sys.exit(1)
        if not 0 <= args.te <= 20 or args.te % 2 != 0:
            print(f"Error: TE must be even 0-20, got {args.te}", file=sys.stderr)
            sys.exit(1)
        print(generate_report(d, args.target, args.me, args.te, args.waste), end='')
    elif args.command == 'invention':
        print(generate_invention_report(d, args.target, args.skill), end='')
    elif args.command == 'plan':
        try:
            params = parse_build_string(args.build_string)
        except ValueError as e:
            print(f"Error: {e}", file=sys.stderr)
            sys.exit(1)
        cfg = load_yaml_file(Path(args.config))
        print(generate_plan(d, params, cfg, Path(args.output)), end='')


if __name__ == '__main__':
    main()

#!/usr/bin/env python3
"""EVE Online Industrial Planner - Parse SDE and emit recipe reports."""

import argparse
import bz2
import csv
import math
import sys
from pathlib import Path
from collections import defaultdict
from dataclasses import dataclass
from typing import Optional, field

import yaml


def load_csv_bz2(filepath: Path):
    with bz2.open(filepath, 'rt', encoding='utf-8') as f:
        return list(csv.DictReader(f))


def load_yaml_file(filepath: Path):
    with open(filepath, 'r', encoding='utf-8') as f:
        return yaml.safe_load(f)


@dataclass
class BuildParams:
    item_name: str
    runs_per_job: int
    num_jobs: int
    me: int = 0
    te: int = 0
    decryptor: str = 'None'
    relic: Optional[str] = None
    build_type: str = 'normal'
    build_all: bool = False


@dataclass
class SDEData:
    types: dict = field(default_factory=dict)
    groups: dict = field(default_factory=dict)
    categories: dict = field(default_factory=dict)
    market_groups: dict = field(default_factory=dict)
    meta_types: dict = field(default_factory=dict)
    meta_groups: dict = field(default_factory=dict)
    activities: dict = field(default_factory=lambda: defaultdict(dict))
    products: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(dict)))
    materials: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(list)))
    probabilities: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(dict)))
    skills: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(list)))
    activity_names: dict = field(default_factory=dict)
    ship_volumes: dict = field(default_factory=dict)
    buildable_types: set = field(default_factory=set)
    inventable_by_product: dict = field(default_factory=dict)
    blueprint_names: dict = field(default_factory=dict)


def parse_sde(sde_dir: Path) -> SDEData:
    data = SDEData()

    for row in load_csv_bz2(sde_dir / 'invTypes.csv.bz2'):
        if int(row.get('published', 0)) != 1:
            continue
        tid = int(row['typeID'])
        data.types[tid] = {
            'typeID': tid,
            'groupID': int(row['groupID']),
            'typeName': row['typeName'],
            'volume': row.get('volume', '0'),
            'marketGroupID': int(row['marketGroupID']) if row.get('marketGroupID') and row['marketGroupID'] != 'None' else None,
            'mass': row.get('mass', '0'),
            'raceID': row.get('raceID'),
            'basePrice': row.get('basePrice'),
            'description': row.get('description', ''),
        }

    for row in load_csv_bz2(sde_dir / 'invGroups.csv.bz2'):
        if int(row.get('published', 0)) != 1:
            continue
        gid = int(row['groupID'])
        data.groups[gid] = {
            'groupID': gid,
            'categoryID': int(row['categoryID']),
            'groupName': row['groupName'],
            'iconID': row.get('iconID'),
        }

    for row in load_csv_bz2(sde_dir / 'invCategories.csv.bz2'):
        if int(row.get('published', 0)) != 1:
            continue
        cid = int(row['categoryID'])
        data.categories[cid] = {
            'categoryID': cid,
            'categoryName': row['categoryName'],
            'iconID': row.get('iconID'),
        }

    for row in load_csv_bz2(sde_dir / 'invMarketGroups.csv.bz2'):
        mg_id = int(row['marketGroupID'])
        parent_id = int(row['parentGroupID']) if row.get('parentGroupID') and row['parentGroupID'] != 'None' else None
        data.market_groups[mg_id] = {
            'marketGroupID': mg_id,
            'parentGroupID': parent_id,
            'marketGroupName': row['marketGroupName'],
            'description': row.get('description', ''),
            'iconID': row.get('iconID'),
            'hasTypes': int(row.get('hasTypes', 0)) == 1,
        }

    for row in load_csv_bz2(sde_dir / 'invMetaTypes.csv.bz2'):
        if row.get('metaGroupID'):
            data.meta_types[int(row['typeID'])] = int(row['metaGroupID'])

    for row in load_csv_bz2(sde_dir / 'invMetaGroups.csv.bz2'):
        data.meta_groups[int(row['metaGroupID'])] = row['metaGroupName']

    for row in load_csv_bz2(sde_dir / 'industryActivity.csv.bz2'):
        data.activities[int(row['typeID'])][int(row['activityID'])] = int(row['time'])

    for row in load_csv_bz2(sde_dir / 'industryActivityProducts.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        pid = int(row['productTypeID'])
        data.products[tid][aid][pid] = int(row['quantity'])

    for row in load_csv_bz2(sde_dir / 'industryActivityMaterials.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        data.materials[tid][aid].append({'typeID': int(row['materialTypeID']), 'quantity': int(row['quantity'])})

    for row in load_csv_bz2(sde_dir / 'industryActivityProbabilities.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        pid = int(row['productTypeID'])
        data.probabilities[tid][aid][pid] = float(row['probability'])

    for row in load_csv_bz2(sde_dir / 'industryActivitySkills.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        data.skills[tid][aid].append({'skillID': int(row['skillID']), 'level': int(row['level'])})

    for row in load_csv_bz2(sde_dir / 'ramActivities.csv.bz2'):
        if row.get('published') == '1':
            data.activity_names[int(row['activityID'])] = row['activityName']

    data.ship_volumes = {k: float(v) for k, v in load_yaml_file(sde_dir / 'ship_volumes.yaml').items()}

    for tid, acts in data.products.items():
        if 1 in acts or 8 in acts:
            data.buildable_types.add(tid)
        if 8 in acts:
            for pid in acts[8]:
                data.inventable_by_product[pid] = (tid, 8)

    for tid, tdata in data.types.items():
        if 'Blueprint' in tdata['typeName']:
            data.blueprint_names[tdata['typeName']] = tid

    return data


INVENTION = 8
MANUFACTURING = 1


def get_type_name(data: SDEData, tid: int) -> str:
    return data.types.get(tid, {}).get('typeName', '')


def get_group_path(data: SDEData, tid: int):
    tdata = data.types.get(tid)
    if not tdata:
        return 'Unknown', 'Unknown'
    gdata = data.groups.get(tdata['groupID'])
    if not gdata:
        return 'Unknown', 'Unknown'
    if cdata := data.categories.get(gdata['categoryID']):
        return cdata['categoryName'], gdata['groupName']
    return 'Unknown', gdata['groupName']


def get_market_group_path(data: SDEData, tid: int):
    tdata = data.types.get(tid)
    if not tdata or not tdata.get('marketGroupID'):
        return None
    path_parts = []
    mg_id = tdata['marketGroupID']
    while mg_id is not None:
        mgdata = data.market_groups.get(mg_id)
        if not mgdata:
            break
        path_parts.append(mgdata['marketGroupName'])
        mg_id = mgdata.get('parentGroupID')
    return ' > '.join(reversed(path_parts)) if path_parts else None


def get_tech_level(data: SDEData, tid: int) -> str:
    meta_id = data.meta_types.get(tid)
    if not meta_id:
        return 'Tech I'
    meta_name = data.meta_groups.get(meta_id, '')
    return meta_name if meta_name in ('Tech II', 'Tech III') else 'Tech I'


def get_volume(data: SDEData, tid: int) -> float:
    tdata = data.types.get(tid)
    if not tdata:
        return 0.0
    _, gname = get_group_path(data, tid)
    if gname in data.ship_volumes:
        return data.ship_volumes[gname]
    try:
        return float(tdata.get('volume') or '0')
    except ValueError:
        return 0.0


def get_invention_data(data: SDEData, pid: int, skill_level: int) -> Optional[dict]:
    bid, _ = data.inventable_by_product.get(pid, (None, None))
    if not bid:
        return None

    time_minutes = math.ceil(data.activities.get(bid, {}).get(INVENTION, 0) / 60)

    dc_materials = data.materials.get(bid, {}).get(INVENTION, [])
    datacores = []
    for mat in dc_materials:
        mname = get_type_name(data, mat['typeID'])
        if mname and mname.startswith('Datacore - '):
            datacores.append({'typeID': mat['typeID'], 'name': mname, 'quantity': mat['quantity']})

    skill_list = data.skills.get(bid, {}).get(INVENTION, [])
    skills = [{'name': get_type_name(data, s['skillID']), 'required_level': s['level']} for s in skill_list]

    base_prob = data.probabilities.get(bid, {}).get(INVENTION, {}).get(pid, 0.0)

    return {
        'invention_blueprint_id': bid,
        'time_minutes': time_minutes,
        'datacores': datacores,
        'skills': skills,
        'base_probability': base_prob,
        'tech_level': get_tech_level(data, pid)
    }


def get_recipe(data: SDEData, tid: int, me: int = 0) -> Optional[dict]:
    acts = data.products.get(tid, {})
    if MANUFACTURING not in acts:
        return None

    time_raw = data.activities.get(tid, {}).get(MANUFACTURING, 0)
    materials = data.materials.get(tid, {}).get(MANUFACTURING, [])

    if me > 0:
        materials = [{'typeID': m['typeID'], 'quantity': math.ceil(max(1, m['quantity'] * (1 - me / 100))), 'original_quantity': m['quantity']} for m in materials]
    else:
        materials = [{'typeID': m['typeID'], 'quantity': m['quantity'], 'original_quantity': m['quantity']} for m in materials]

    return {
        'activity': data.activity_names.get(MANUFACTURING, 'Manufacturing'),
        'output_qty': sum(acts[MANUFACTURING].values()),
        'run_time': round(time_raw / 60),
        'materials': materials
    }


def find_product_by_name(data: SDEData, name: str, bp_lookup: bool = True):
    for tid, tdata in data.types.items():
        if tdata['typeName'] == name:
            return tdata, tid, False
    if bp_lookup:
        for bp_name, bid in data.blueprint_names.items():
            if bp_name == name:
                return data.types.get(bid), bid, True
    return None, None, False


def calculate_probability(base_prob: float, skill_level: int, decryptor: str) -> float:
    mult = base_prob * (1 + 7 * skill_level / 120)
    dec = DECRYPTORS.get(decryptor, (0, 0, 0, 0))
    return max(0.0, min(1.0, mult * (1 + dec[0] / 100.0)))


DECRYPTORS = {
    'None': (0, 0, 0, 0),
    'Accelerant Decryptor': (20, 1, 2, 10),
    'Attainment Decryptor': (80, 4, -1, 4),
    'Augmentation Decryptor': (-40, 9, -2, 2),
    'Optimized Attainment Decryptor': (90, 2, 1, -2),
    'Optimized Augmentation Decryptor': (-10, 7, 2, 0),
    'Parity Decryptor': (50, 3, 1, -2),
    'Process Decryptor': (10, 0, 3, 6),
    'Symmetry Decryptor': (0, 2, 1, 8),
}

TECHIII_RELICS = {'Intact': 0.26, 'Malfunctioning': 0.21, 'Wrecked': 0.14}
TECHIII_BASE_RUNS = {'Intact': 20, 'Malfunctioning': 10, 'Wrecked': 3}


def parse_build_string(build_str: str) -> BuildParams:
    parts = build_str.strip().split()
    if len(parts) < 2:
        raise ValueError(f"Invalid build string format: {build_str}")

    num_jobs = 1
    x_idx = next((i for i, p in enumerate(parts) if p.lower().startswith('x')), -1)
    if x_idx >= 0:
        num_jobs = int(parts[x_idx][1:])
        parts = parts[:x_idx] + parts[x_idx+1:]

    # Find first numeric token
    first_num = next((i for i, p in enumerate(parts) if p.isdigit()), -1)
    if first_num <= 0:
        raise ValueError(f"Invalid build string format: {build_str}")

    item_name = ' '.join(parts[:first_num])
    tokens = parts[first_num:]

    if len(tokens) == 1:
        return BuildParams(item_name, int(tokens[0]), num_jobs)
    if len(tokens) == 2:
        try:
            return BuildParams(item_name, int(tokens[0]), num_jobs, me=int(tokens[1]))
        except ValueError:
            return BuildParams(item_name, int(tokens[0]), num_jobs, decryptor=tokens[1], build_type='invention')
    if len(tokens) == 3:
        return BuildParams(item_name, int(tokens[0]), num_jobs, me=int(tokens[1]), te=int(tokens[2]))
    if len(tokens) == 4:
        return BuildParams(item_name, int(tokens[0]), num_jobs, decryptor=tokens[1], relic=tokens[2], build_type='re')

    raise ValueError(f"Invalid build string format. Unexpected argument count: {build_str}")


def generate_invention_report(data: SDEData, name: str, skill: int) -> str:
    tdata, tid, is_bp = find_product_by_name(data, name)
    if not tdata:
        return f"Error: Item '{name}' not found or not published.\n"

    if is_bp:
        inv = data.products.get(tid, {}).get(INVENTION, {})
        if inv:
            tid = next(iter(inv.keys()))
            tdata = data.types.get(tid)
        else:
            return f"Error: '{name}' is not an inventable blueprint.\n"

    inv = get_invention_data(data, tid, skill)
    if not inv:
        return f"Error: '{name}' is not an inventable item.\n"

    tech = inv['tech_level']
    if tech not in ('Tech II', 'Tech III'):
        return f"Error: '{name}' is not Tech II or Tech III.\n"

    cat, grp = get_group_path(data, tid)
    mg = get_market_group_path(data, tid)

    lines = [
        f"ITEM: {tdata['typeName']} ({tid})",
        f"Group: {cat} > {grp}",
        f"Market Group: {mg if mg else 'None'}",
        f"Tech Level: {tech}",
        "",
        "Invention:",
    ]

    if tech == 'Tech II':
        lines.append(f"Base: {get_type_name(data, inv['invention_blueprint_id'])} ({inv['invention_blueprint_id']})")

    dc = sorted(inv['datacores'], key=lambda d: d['name'].lower())
    lines.append(f"Datacores: {', '.join(d['name'] for d in dc)}")
    lines.append(f"Required Per Run: {dc[0]['quantity'] if dc else 0}")

    sk = sorted(inv['skills'], key=lambda s: s['name'].lower())
    lines.append(f"Skills: {', '.join(s['name'] for s in sk)}")
    lines.append(f"Time: {inv['time_minutes']}")

    if tech == 'Tech II':
        base_bp = inv['invention_blueprint_id']
        base_runs = data.products.get(base_bp, {}).get(INVENTION, {}).get(tid, 10)
        lines.extend(["Probabilities:", "| Decryptor                       | Probability | Runs | ME | TE |", "|---------------------------------|-------------|------|----|----|"])
        for dname in sorted(DECRYPTORS.keys(), key=str.lower):
            prob = calculate_probability(inv['base_probability'], skill, dname)
            _, dr, dme, dte = DECRYPTORS[dname]
            lines.append(f"| {dname:<31} | {prob:>9.2f} | {base_runs + dr:>4} | {2 + dme:>2} | {4 + dte:>2} |")
    else:
        lines.extend(["Probabilities:", "| Invented From                | Decryptor                       | Probability | Runs | ME | TE |", "|------------------------------|---------------------------------|-------------|------|----|----|"])
        for rel in ('Intact', 'Malfunctioning', 'Wrecked'):
            for dname in sorted(DECRYPTORS.keys(), key=str.lower):
                prob = calculate_probability(TECHIII_RELICS[rel], skill, dname)
                _, dr, dme, dte = DECRYPTORS[dname]
                lines.append(f"| {rel:<28} | {dname:<31} | {prob:>9.2f} | {TECHIII_BASE_RUNS[rel] + dr:>4} | {2 + dme:>2} | {4 + dte:>2} |")

    return '\n'.join(lines) + '\n'


def write_jobs_csv(path: Path, name: str, runs: int, days: float, count: int):
    with open(path, 'w', newline='', encoding='utf-8') as f:
        w = csv.writer(f)
        w.writerow(['name', 'runs', 'days', 'count'])
        w.writerow([name, runs, days, count])


def write_materials_csv(path: Path, mat_data: dict):
    with open(path, 'w', newline='', encoding='utf-8') as f:
        w = csv.writer(f)
        w.writerow(['name', 'to_buy', 'buy_volume', 'start_amount', 'end_amount'])
        for name in sorted(mat_data.keys()):
            qty = mat_data[name]
            w.writerow([name, qty, round(qty / 10, 1), 0, 0])


def resolve_blueprint_product(data: SDEData, bid: int):
    for pid, acts in data.products.items():
        if pid == bid:
            for act in acts.values():
                if act:
                    product_id = next(iter(act.keys()))
                    return product_id, data.types.get(product_id)
    return None, None


def generate_plan(data: SDEData, params: BuildParams, config: dict, out_dir: Path) -> str:
    out_dir.mkdir(parents=True, exist_ok=True)

    tdata, tid, found_bp = find_product_by_name(data, params.item_name)
    if not tdata:
        return f"Error: Item '{params.item_name}' not found or not published.\n"

    bid = tid if found_bp else None
    if bid:
        tid, tdata = resolve_blueprint_product(data, bid)
        if not tid:
            return f"Error: No product found for blueprint.\n"

    if params.build_type in ('invention', 're'):
        return _gen_invention_plan(data, params, config, out_dir, tid, bid)
    return _gen_manufacturing_plan(data, params, config, out_dir, tid, bid)


def _gen_invention_plan(data: SDEData, params: BuildParams, config: dict, out_dir: Path, tid: int, bid: int):
    inv = get_invention_data(data, tid, config.get('invention_skill', 3))
    if not inv:
        return f"Error: item not inventable.\n"

    prob = calculate_probability(inv['base_probability'], config.get('invention_skill', 3), params.decryptor)
    _, dr, _, _ = DECRYPTORS.get(params.decryptor, (0, 0, 0, 0))

    rel = params.relic or 'Malfunctioning'
    base_runs = TECHIII_BASE_RUNS.get(rel, 10) if params.build_type == 're' else data.products.get(inv['invention_blueprint_id'], {}).get(INVENTION, {}).get(tid, 10)
    runs = base_runs + dr

    total_runs = params.num_jobs * params.runs_per_job
    exp_bp_runs = math.ceil(total_runs / (runs * prob))

    dc_materials = data.materials.get(inv['invention_blueprint_id'], {}).get(INVENTION, [])
    dc_data = {}
    for mat in dc_materials:
        mname = get_type_name(data, mat['typeID'])
        if mname and mname.startswith('Datacore - '):
            dc_data[mname] = dc_data.get(mname, 0) + mat['quantity'] * exp_bp_runs

    write_materials_csv(out_dir / 'materials.csv', dc_data)

    invent_time = inv['time_minutes'] * exp_bp_runs
    bp_name = get_type_name(data, inv['invention_blueprint_id']) or f"Blueprint {inv['invention_blueprint_id']}"
    write_jobs_csv(out_dir / 'jobs.csv', f"{bp_name} Blueprints", exp_bp_runs, math.ceil(invent_time / 60 / 24 * 100) / 100, 1)

    return f"Plan generated: {out_dir / 'materials.csv'}, {out_dir / 'jobs.csv'}\n"


def _gen_manufacturing_plan(data: SDEData, params: BuildParams, config: dict, out_dir: Path, tid: int, bid: int):
    # Find blueprint if not provided
    if not bid:
        for pid, acts in data.products.items():
            if MANUFACTURING in acts and tid in acts[MANUFACTURING]:
                bid = pid
                break
        if not bid:
            return f"Error: No manufacturing blueprint found.\n"

    bp_time = data.activities.get(bid, {}).get(MANUFACTURING, 0)
    if bp_time == 0:
        bp_time = data.activities.get(tid, {}).get(MANUFACTURING, 0)

    te_bonus = config.get('te_bonus', 20)
    full_te = bp_time * (1 - params.te / 100) * (1 - te_bonus / 100)
    run_days = full_te / 60 / 24

    materials = [{'typeID': m['typeID'], 'quantity': math.ceil(max(1, m['quantity'] * (1 - params.me / 100))), 'original_quantity': m['quantity']} for m in data.materials.get(bid, {}).get(MANUFACTURING, [])]

    total_runs = params.num_jobs * params.runs_per_job
    mat_total = {}
    for mat in materials:
        name = get_type_name(data, mat['typeID']) or f'Type {mat["typeID"]}'
        mat_total[name] = mat_total.get(name, 0) + mat['quantity'] * total_runs

    write_materials_csv(out_dir / 'materials.csv', mat_total)

    bp_name = get_type_name(data, bid) or f"Blueprint {bid}"
    with open(out_dir / 'jobs.csv', 'w', newline='', encoding='utf-8') as f:
        w = csv.writer(f)
        w.writerow(['name', 'runs', 'days', 'count'])
        for j in range(1, params.num_jobs + 1):
            w.writerow([bp_name, params.runs_per_job, round(run_days * params.runs_per_job, 2), j])

    return f"Plan generated: {out_dir / 'materials.csv'}, {out_dir / 'jobs.csv'}\n"


def generate_report(data: SDEData, name: str, me: int = 0, te: int = 0, waste: bool = False) -> str:
    tdata, tid, found_bp = find_product_by_name(data, name)
    if not tdata:
        return f"Error: Item '{name}' not found or not published.\n"

    bid = tid if found_bp else None
    disp_tid, disp_tdata = tid, tdata
    if bid:
        disp_tid, disp_tdata = resolve_blueprint_product(data, bid) or (tid, tdata)

    recipe = get_recipe(data, disp_tid, me)
    if not recipe:
        return f"Error: No industry activity found for '{name}'.\n"

    cat, grp = get_group_path(data, disp_tid)
    mg = get_market_group_path(data, disp_tid)
    tech = get_tech_level(data, disp_tid)
    vol = get_volume(data, disp_tid)

    run_time = round(recipe['run_time'] * (1 - te / 100)) if te > 0 else recipe['run_time']

    def mat_row(m):
        mname = get_type_name(data, m['typeID']) or 'Unknown'
        buildable = 'Yes' if any(a in data.buildable_types for a in [m['typeID']]) else 'No'
        if waste:
            return f"| {mname} | {m['quantity']} | {m['original_quantity'] - m['quantity']} | {buildable} |"
        return f"| {mname} | {m['quantity']} | {buildable} |"

    header = "| Item | Quantity | Waste | Buildable |" if waste else "| Item | Quantity | Buildable |"
    sep = "|:-:|:-:|:-:|---:|" if waste else "|:-:|:---:|---:|"

    lines = [
        f"ITEM: {disp_tdata['typeName']} ({disp_tid})",
        f"Group: {cat} > {grp}",
        f"Market Group: {mg if mg else 'None'}",
        f"Tech Level: {tech}",
        f"Volume: {vol:.2f}",
        "",
        "Recipe:",
        f"Activity: {recipe['activity']}",
        f"Output Quantity: {recipe['output_qty']}",
        f"Run Time: {run_time}",
        header,
        sep,
    ]
    for mat in sorted(recipe['materials'], key=lambda m: (get_type_name(data, m['typeID']) or '').lower()):
        lines.append(mat_row(mat))

    return '\n'.join(lines) + '\n'


def main():
    p = argparse.ArgumentParser(description='EVE Online Industrial Planner')
    s = p.add_subparsers(dest='command')

    r = s.add_parser('recipe', help='Generate recipe report')
    r.add_argument('target')
    r.add_argument('--sde', required=True)
    r.add_argument('--me', type=int, default=0)
    r.add_argument('--te', type=int, default=0)
    r.add_argument('--waste', action='store_true')

    inv = s.add_parser('invention', help='Generate invention report')
    inv.add_argument('target')
    inv.add_argument('--sde', required=True)
    inv.add_argument('--skill', type=int, choices=range(1, 6), default=5)

    pl = s.add_parser('plan', help='Create build plan')
    pl.add_argument('build_string')
    pl.add_argument('--config', required=True)
    pl.add_argument('--sde', required=True)
    pl.add_argument('--output', required=True)
    pl.add_argument('--build-all', action='store_true', help='Build all components in the dependency tree')

    args = p.parse_args()
    if not args.command:
        p.print_help()
        sys.exit(1)

    sde_path = Path(args.sde)
    if not sde_path.exists():
        print(f"Error: SDE '{args.sde}' not found.", file=sys.stderr)
        sys.exit(1)

    d = parse_sde(sde_path)

    if args.command == 'recipe':
        if not 0 <= args.me <= 10:
            print(f"Error: ME must be 0-10, got {args.me}", file=sys.stderr)
            sys.exit(1)
        if not 0 <= args.te <= 20 or args.te % 2 != 0:
            print(f"Error: TE must be even 0-20, got {args.te}", file=sys.stderr)
            sys.exit(1)
        print(generate_report(d, args.target, args.me, args.te, args.waste), end='')
    elif args.command == 'invention':
        print(generate_invention_report(d, args.target, args.skill), end='')
    elif args.command == 'plan':
        try:
            params = parse_build_string(args.build_string)
        except ValueError as e:
            print(f"Error: {e}", file=sys.stderr)
            sys.exit(1)
        cfg = load_yaml_file(Path(args.config))
        print(generate_plan(d, params, cfg, Path(args.output)), end='')


if __name__ == '__main__':
    main()

#!/usr/bin/env python3
"""EVE Online Industrial Planner - Parse SDE and emit recipe reports."""

import argparse
import bz2
import csv
import math
import sys
from pathlib import Path
from collections import defaultdict
from dataclasses import dataclass
from typing import Optional, field

import yaml


def load_csv_bz2(filepath: Path):
    with bz2.open(filepath, 'rt', encoding='utf-8') as f:
        return list(csv.DictReader(f))


def load_yaml_file(filepath: Path):
    with open(filepath, 'r', encoding='utf-8') as f:
        return yaml.safe_load(f)


@dataclass
class BuildParams:
    item_name: str
    runs_per_job: int
    num_jobs: int
    me: int = 0
    te: int = 0
    decryptor: str = 'None'
    relic: Optional[str] = None
    build_type: str = 'normal'
    build_all: bool = False


@dataclass
class SDEData:
    types: dict = field(default_factory=dict)
    groups: dict = field(default_factory=dict)
    categories: dict = field(default_factory=dict)
    market_groups: dict = field(default_factory=dict)
    meta_types: dict = field(default_factory=dict)
    meta_groups: dict = field(default_factory=dict)
    activities: dict = field(default_factory=lambda: defaultdict(dict))
    products: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(dict)))
    materials: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(list)))
    probabilities: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(dict)))
    skills: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(list)))
    activity_names: dict = field(default_factory=dict)
    ship_volumes: dict = field(default_factory=dict)
    buildable_types: set = field(default_factory=set)
    inventable_by_product: dict = field(default_factory=dict)
    blueprint_names: dict = field(default_factory=dict)


def parse_sde(sde_dir: Path) -> SDEData:
    data = SDEData()

    for row in load_csv_bz2(sde_dir / 'invTypes.csv.bz2'):
        if int(row.get('published', 0)) != 1:
            continue
        tid = int(row['typeID'])
        data.types[tid] = {
            'typeID': tid,
            'groupID': int(row['groupID']),
            'typeName': row['typeName'],
            'volume': row.get('volume', '0'),
            'marketGroupID': int(row['marketGroupID']) if row.get('marketGroupID') and row['marketGroupID'] != 'None' else None,
            'mass': row.get('mass', '0'),
            'raceID': row.get('raceID'),
            'basePrice': row.get('basePrice'),
            'description': row.get('description', ''),
        }

    for row in load_csv_bz2(sde_dir / 'invGroups.csv.bz2'):
        if int(row.get('published', 0)) != 1:
            continue
        gid = int(row['groupID'])
        data.groups[gid] = {
            'groupID': gid,
            'categoryID': int(row['categoryID']),
            'groupName': row['groupName'],
            'iconID': row.get('iconID'),
        }

    for row in load_csv_bz2(sde_dir / 'invCategories.csv.bz2'):
        if int(row.get('published', 0)) != 1:
            continue
        cid = int(row['categoryID'])
        data.categories[cid] = {
            'categoryID': cid,
            'categoryName': row['categoryName'],
            'iconID': row.get('iconID'),
        }

    for row in load_csv_bz2(sde_dir / 'invMarketGroups.csv.bz2'):
        mg_id = int(row['marketGroupID'])
        parent_id = int(row['parentGroupID']) if row.get('parentGroupID') and row['parentGroupID'] != 'None' else None
        data.market_groups[mg_id] = {
            'marketGroupID': mg_id,
            'parentGroupID': parent_id,
            'marketGroupName': row['marketGroupName'],
            'description': row.get('description', ''),
            'iconID': row.get('iconID'),
            'hasTypes': int(row.get('hasTypes', 0)) == 1,
        }

    for row in load_csv_bz2(sde_dir / 'invMetaTypes.csv.bz2'):
        if row.get('metaGroupID'):
            data.meta_types[int(row['typeID'])] = int(row['metaGroupID'])

    for row in load_csv_bz2(sde_dir / 'invMetaGroups.csv.bz2'):
        data.meta_groups[int(row['metaGroupID'])] = row['metaGroupName']

    for row in load_csv_bz2(sde_dir / 'industryActivity.csv.bz2'):
        data.activities[int(row['typeID'])][int(row['activityID'])] = int(row['time'])

    for row in load_csv_bz2(sde_dir / 'industryActivityProducts.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        pid = int(row['productTypeID'])
        data.products[tid][aid][pid] = int(row['quantity'])

    for row in load_csv_bz2(sde_dir / 'industryActivityMaterials.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        data.materials[tid][aid].append({'typeID': int(row['materialTypeID']), 'quantity': int(row['quantity'])})

    for row in load_csv_bz2(sde_dir / 'industryActivityProbabilities.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        pid = int(row['productTypeID'])
        data.probabilities[tid][aid][pid] = float(row['probability'])

    for row in load_csv_bz2(sde_dir / 'industryActivitySkills.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        data.skills[tid][aid].append({'skillID': int(row['skillID']), 'level': int(row['level'])})

    for row in load_csv_bz2(sde_dir / 'ramActivities.csv.bz2'):
        if row.get('published') == '1':
            data.activity_names[int(row['activityID'])] = row['activityName']

    data.ship_volumes = {k: float(v) for k, v in load_yaml_file(sde_dir / 'ship_volumes.yaml').items()}

    for tid, acts in data.products.items():
        if 1 in acts or 8 in acts:
            data.buildable_types.add(tid)
        if 8 in acts:
            for pid in acts[8]:
                data.inventable_by_product[pid] = (tid, 8)

    for tid, tdata in data.types.items():
        if 'Blueprint' in tdata['typeName']:
            data.blueprint_names[tdata['typeName']] = tid

    return data


INVENTION = 8
MANUFACTURING = 1


def get_type_name(data: SDEData, tid: int) -> str:
    return data.types.get(tid, {}).get('typeName', '')


def get_group_path(data: SDEData, tid: int):
    tdata = data.types.get(tid)
    if not tdata:
        return 'Unknown', 'Unknown'
    gdata = data.groups.get(tdata['groupID'])
    if not gdata:
        return 'Unknown', 'Unknown'
    if cdata := data.categories.get(gdata['categoryID']):
        return cdata['categoryName'], gdata['groupName']
    return 'Unknown', gdata['groupName']


def get_market_group_path(data: SDEData, tid: int):
    tdata = data.types.get(tid)
    if not tdata or not tdata.get('marketGroupID'):
        return None
    path_parts = []
    mg_id = tdata['marketGroupID']
    while mg_id is not None:
        mgdata = data.market_groups.get(mg_id)
        if not mgdata:
            break
        path_parts.append(mgdata['marketGroupName'])
        mg_id = mgdata.get('parentGroupID')
    return ' > '.join(reversed(path_parts)) if path_parts else None


def get_tech_level(data: SDEData, tid: int) -> str:
    meta_id = data.meta_types.get(tid)
    if not meta_id:
        return 'Tech I'
    meta_name = data.meta_groups.get(meta_id, '')
    return meta_name if meta_name in ('Tech II', 'Tech III') else 'Tech I'


def get_volume(data: SDEData, tid: int) -> float:
    tdata = data.types.get(tid)
    if not tdata:
        return 0.0
    _, gname = get_group_path(data, tid)
    if gname in data.ship_volumes:
        return data.ship_volumes[gname]
    try:
        return float(tdata.get('volume') or '0')
    except ValueError:
        return 0.0


def get_invention_data(data: SDEData, pid: int, skill_level: int) -> Optional[dict]:
    bid, _ = data.inventable_by_product.get(pid, (None, None))
    if not bid:
        return None

    time_minutes = math.ceil(data.activities.get(bid, {}).get(INVENTION, 0) / 60)

    dc_materials = data.materials.get(bid, {}).get(INVENTION, [])
    datacores = []
    for mat in dc_materials:
        mname = get_type_name(data, mat['typeID'])
        if mname and mname.startswith('Datacore - '):
            datacores.append({'typeID': mat['typeID'], 'name': mname, 'quantity': mat['quantity']})

    skill_list = data.skills.get(bid, {}).get(INVENTION, [])
    skills = [{'name': get_type_name(data, s['skillID']), 'required_level': s['level']} for s in skill_list]

    base_prob = data.probabilities.get(bid, {}).get(INVENTION, {}).get(pid, 0.0)

    return {
        'invention_blueprint_id': bid,
        'time_minutes': time_minutes,
        'datacores': datacores,
        'skills': skills,
        'base_probability': base_prob,
        'tech_level': get_tech_level(data, pid)
    }


def get_recipe(data: SDEData, tid: int, me: int = 0) -> Optional[dict]:
    acts = data.products.get(tid, {})
    if MANUFACTURING not in acts:
        return None

    time_raw = data.activities.get(tid, {}).get(MANUFACTURING, 0)
    materials = data.materials.get(tid, {}).get(MANUFACTURING, [])

    if me > 0:
        materials = [{'typeID': m['typeID'], 'quantity': math.ceil(max(1, m['quantity'] * (1 - me / 100))), 'original_quantity': m['quantity']} for m in materials]
    else:
        materials = [{'typeID': m['typeID'], 'quantity': m['quantity'], 'original_quantity': m['quantity']} for m in materials]

    return {
        'activity': data.activity_names.get(MANUFACTURING, 'Manufacturing'),
        'output_qty': sum(acts[MANUFACTURING].values()),
        'run_time': round(time_raw / 60),
        'materials': materials
    }


def find_product_by_name(data: SDEData, name: str, bp_lookup: bool = True):
    for tid, tdata in data.types.items():
        if tdata['typeName'] == name:
            return tdata, tid, False
    if bp_lookup:
        for bp_name, bid in data.blueprint_names.items():
            if bp_name == name:
                return data.types.get(bid), bid, True
    return None, None, False


def calculate_probability(base_prob: float, skill_level: int, decryptor: str) -> float:
    mult = base_prob * (1 + 7 * skill_level / 120)
    dec = DECRYPTORS.get(decryptor, (0, 0, 0, 0))
    return max(0.0, min(1.0, mult * (1 + dec[0] / 100.0)))


DECRYPTORS = {
    'None': (0, 0, 0, 0),
    'Accelerant Decryptor': (20, 1, 2, 10),
    'Attainment Decryptor': (80, 4, -1, 4),
    'Augmentation Decryptor': (-40, 9, -2, 2),
    'Optimized Attainment Decryptor': (90, 2, 1, -2),
    'Optimized Augmentation Decryptor': (-10, 7, 2, 0),
    'Parity Decryptor': (50, 3, 1, -2),
    'Process Decryptor': (10, 0, 3, 6),
    'Symmetry Decryptor': (0, 2, 1, 8),
}


def split_job_runs(total_runs: int, split_days: float, days_per_run: float) -> list[tuple[int, int]]:
    """
    Split a job into multiple jobs based on the split_days threshold.

    Args:
        total_runs: Total number of runs needed
        split_days: Minimum number of days a job must take before being split
        days_per_run: Days per single run (real time after TE reduction)

    Returns:
        List of (runs, count) tuples representing the split jobs

    Formula from specification:
        max_runs = floor(split_days / days_per_run)
        t = ceil(N / max_runs)
        B = N // t
        x = N % t

        if B + 1 == max_runs and x > t/2 and N // (t+1) + 1 < max_runs:
            t = t + 1
            B = N // t
            x = N % t

        output: x jobs of (B+1), (t-x) jobs of B
    """
    # If no runs or days_per_run is 0, return as-is
    if total_runs <= 0 or days_per_run == 0:
        return [(total_runs, 1)]

    # Calculate the threshold based on split_days
    max_days_threshold = min(30, split_days)

    # Check if total time exceeds threshold
    if total_runs * days_per_run <= max_days_threshold:
        return [(total_runs, 1)]

    # Calculate max runs per job before splitting is needed
    max_runs = int(max_days_threshold // days_per_run)

    # Can't split if less than 2 runs or max_runs < 2
    if max_runs < 2:
        return [(total_runs, 1)]

    N = total_runs

    # If total runs don't exceed max_runs, return as-is
    if N <= max_runs:
        return [(N, 1)]

    # Apply the splitting formula
    t = (N + max_runs - 1) // max_runs  # ceil(N / max_runs)
    B = N // t
    x = N % t

    if B + 1 == max_runs and x > t / 2 and N // (t + 1) + 1 < max_runs:
        t = t + 1
        B = N // t
        x = N % t

    result = []
    # x jobs of (B+1) runs
    if x > 0:
        result.append((B + 1, x))
    # (t-x) jobs of B runs
    if t - x > 0:
        result.append((B, t - x))

    return result

TECHIII_RELICS = {'Intact': 0.26, 'Malfunctioning': 0.21, 'Wrecked': 0.14}
TECHIII_BASE_RUNS = {'Intact': 20, 'Malfunctioning': 10, 'Wrecked': 3}


def parse_build_string(build_str: str) -> BuildParams:
    parts = build_str.strip().split()
    if len(parts) < 2:
        raise ValueError(f"Invalid build string format: {build_str}")

    num_jobs = 1
    x_idx = next((i for i, p in enumerate(parts) if p.lower().startswith('x')), -1)
    if x_idx >= 0:
        num_jobs = int(parts[x_idx][1:])
        parts = parts[:x_idx] + parts[x_idx+1:]

    # Find first numeric token
    first_num = next((i for i, p in enumerate(parts) if p.isdigit()), -1)
    if first_num <= 0:
        raise ValueError(f"Invalid build string format: {build_str}")

    item_name = ' '.join(parts[:first_num])
    tokens = parts[first_num:]

    if len(tokens) == 1:
        return BuildParams(item_name, int(tokens[0]), num_jobs)
    if len(tokens) == 2:
        try:
            return BuildParams(item_name, int(tokens[0]), num_jobs, me=int(tokens[1]))
        except ValueError:
            return BuildParams(item_name, int(tokens[0]), num_jobs, decryptor=tokens[1], build_type='invention')
    if len(tokens) == 3:
        return BuildParams(item_name, int(tokens[0]), num_jobs, me=int(tokens[1]), te=int(tokens[2]))
    if len(tokens) == 4:
        return BuildParams(item_name, int(tokens[0]), num_jobs, decryptor=tokens[1], relic=tokens[2], build_type='re')

    raise ValueError(f"Invalid build string format. Unexpected argument count: {build_str}")


def generate_invention_report(data: SDEData, name: str, skill: int) -> str:
    tdata, tid, is_bp = find_product_by_name(data, name)
    if not tdata:
        return f"Error: Item '{name}' not found or not published.\n"

    if is_bp:
        inv = data.products.get(tid, {}).get(INVENTION, {})
        if inv:
            tid = next(iter(inv.keys()))
            tdata = data.types.get(tid)
        else:
            return f"Error: '{name}' is not an inventable blueprint.\n"

    inv = get_invention_data(data, tid, skill)
    if not inv:
        return f"Error: '{name}' is not an inventable item.\n"

    tech = inv['tech_level']
    if tech not in ('Tech II', 'Tech III'):
        return f"Error: '{name}' is not Tech II or Tech III.\n"

    cat, grp = get_group_path(data, tid)
    mg = get_market_group_path(data, tid)

    lines = [
        f"ITEM: {tdata['typeName']} ({tid})",
        f"Group: {cat} > {grp}",
        f"Market Group: {mg if mg else 'None'}",
        f"Tech Level: {tech}",
        "",
        "Invention:",
    ]

    if tech == 'Tech II':
        lines.append(f"Base: {get_type_name(data, inv['invention_blueprint_id'])} ({inv['invention_blueprint_id']})")

    dc = sorted(inv['datacores'], key=lambda d: d['name'].lower())
    lines.append(f"Datacores: {', '.join(d['name'] for d in dc)}")
    lines.append(f"Required Per Run: {dc[0]['quantity'] if dc else 0}")

    sk = sorted(inv['skills'], key=lambda s: s['name'].lower())
    lines.append(f"Skills: {', '.join(s['name'] for s in sk)}")
    lines.append(f"Time: {inv['time_minutes']}")

    if tech == 'Tech II':
        base_bp = inv['invention_blueprint_id']
        base_runs = data.products.get(base_bp, {}).get(INVENTION, {}).get(tid, 10)
        lines.extend(["Probabilities:", "| Decryptor                       | Probability | Runs | ME | TE |", "|---------------------------------|-------------|------|----|----|"])
        for dname in sorted(DECRYPTORS.keys(), key=str.lower):
            prob = calculate_probability(inv['base_probability'], skill, dname)
            _, dr, dme, dte = DECRYPTORS[dname]
            lines.append(f"| {dname:<31} | {prob:>9.2f} | {base_runs + dr:>4} | {2 + dme:>2} | {4 + dte:>2} |")
    else:
        lines.extend(["Probabilities:", "| Invented From                | Decryptor                       | Probability | Runs | ME | TE |", "|------------------------------|---------------------------------|-------------|------|----|----|"])
        for rel in ('Intact', 'Malfunctioning', 'Wrecked'):
            for dname in sorted(DECRYPTORS.keys(), key=str.lower):
                prob = calculate_probability(TECHIII_RELICS[rel], skill, dname)
                _, dr, dme, dte = DECRYPTORS[dname]
                lines.append(f"| {rel:<28} | {dname:<31} | {prob:>9.2f} | {TECHIII_BASE_RUNS[rel] + dr:>4} | {2 + dme:>2} | {4 + dte:>2} |")

    return '\n'.join(lines) + '\n'


def write_jobs_csv(path: Path, name: str, runs: int, days: float, count: int):
    with open(path, 'w', newline='', encoding='utf-8') as f:
        w = csv.writer(f)
        w.writerow(['name', 'runs', 'days', 'count'])
        w.writerow([name, runs, days, count])


def write_materials_csv(path: Path, mat_data: dict):
    with open(path, 'w', newline='', encoding='utf-8') as f:
        w = csv.writer(f)
        w.writerow(['name', 'to_buy', 'buy_volume', 'start_amount', 'end_amount'])
        for name in sorted(mat_data.keys()):
            qty = mat_data[name]
            w.writerow([name, qty, round(qty / 10, 1), 0, 0])


def resolve_blueprint_product(data: SDEData, bid: int):
    for pid, acts in data.products.items():
        if pid == bid:
            for act in acts.values():
                if act:
                    product_id = next(iter(act.keys()))
                    return product_id, data.types.get(product_id)
    return None, None


def generate_plan(data: SDEData, params: BuildParams, config: dict, out_dir: Path) -> str:
    out_dir.mkdir(parents=True, exist_ok=True)

    tdata, tid, found_bp = find_product_by_name(data, params.item_name)
    if not tdata:
        return f"Error: Item '{params.item_name}' not found or not published.\n"

    bid = tid if found_bp else None
    if bid:
        tid, tdata = resolve_blueprint_product(data, bid)
        if not tid:
            return f"Error: No product found for blueprint.\n"

    if params.build_type in ('invention', 're'):
        return _gen_invention_plan(data, params, config, out_dir, tid, bid)
    return _gen_manufacturing_plan(data, params, config, out_dir, tid, bid)


def _gen_invention_plan(data: SDEData, params: BuildParams, config: dict, out_dir: Path, tid: int, bid: int):
    inv = get_invention_data(data, tid, config.get('invention_skill', 3))
    if not inv:
        return f"Error: item not inventable.\n"

    prob = calculate_probability(inv['base_probability'], config.get('invention_skill', 3), params.decryptor)
    _, dr, _, _ = DECRYPTORS.get(params.decryptor, (0, 0, 0, 0))

    rel = params.relic or 'Malfunctioning'
    base_runs = TECHIII_BASE_RUNS.get(rel, 10) if params.build_type == 're' else data.products.get(inv['invention_blueprint_id'], {}).get(INVENTION, {}).get(tid, 10)
    runs = base_runs + dr

    total_runs = params.num_jobs * params.runs_per_job
    exp_bp_runs = math.ceil(total_runs / (runs * prob))

    dc_materials = data.materials.get(inv['invention_blueprint_id'], {}).get(INVENTION, [])
    dc_data = {}
    for mat in dc_materials:
        mname = get_type_name(data, mat['typeID'])
        if mname and mname.startswith('Datacore - '):
            dc_data[mname] = dc_data.get(mname, 0) + mat['quantity'] * exp_bp_runs

    write_materials_csv(out_dir / 'materials.csv', dc_data)

    invent_time = inv['time_minutes'] * exp_bp_runs
    bp_name = get_type_name(data, inv['invention_blueprint_id']) or f"Blueprint {inv['invention_blueprint_id']}"
    write_jobs_csv(out_dir / 'jobs.csv', f"{bp_name} Blueprints", exp_bp_runs, math.ceil(invent_time / 60 / 24 * 100) / 100, 1)

    return f"Plan generated: {out_dir / 'materials.csv'}, {out_dir / 'jobs.csv'}\n"


def _gen_manufacturing_plan(data: SDEData, params: BuildParams, config: dict, out_dir: Path, tid: int, bid: int):
    # Find blueprint if not provided
    if not bid:
        for pid, acts in data.products.items():
            if MANUFACTURING in acts and tid in acts[MANUFACTURING]:
                bid = pid
                break
        if not bid:
            return f"Error: No manufacturing blueprint found.\n"

    bp_time = data.activities.get(bid, {}).get(MANUFACTURING, 0)
    if bp_time == 0:
        bp_time = data.activities.get(tid, {}).get(MANUFACTURING, 0)

    te_bonus = config.get('te_bonus', 20)
    full_te = bp_time * (1 - params.te / 100) * (1 - te_bonus / 100)
    run_days = full_te / 60 / 24

    materials = [{'typeID': m['typeID'], 'quantity': math.ceil(max(1, m['quantity'] * (1 - params.me / 100))), 'original_quantity': m['quantity']} for m in data.materials.get(bid, {}).get(MANUFACTURING, [])]

    total_runs = params.num_jobs * params.runs_per_job
    mat_total = {}
    for mat in materials:
        name = get_type_name(data, mat['typeID']) or f'Type {mat["typeID"]}'
        mat_total[name] = mat_total.get(name, 0) + mat['quantity'] * total_runs

    write_materials_csv(out_dir / 'materials.csv', mat_total)

    bp_name = get_type_name(data, bid) or f"Blueprint {bid}"
    with open(out_dir / 'jobs.csv', 'w', newline='', encoding='utf-8') as f:
        w = csv.writer(f)
        w.writerow(['name', 'runs', 'days', 'count'])
        for j in range(1, params.num_jobs + 1):
            w.writerow([bp_name, params.runs_per_job, round(run_days * params.runs_per_job, 2), j])

    return f"Plan generated: {out_dir / 'materials.csv'}, {out_dir / 'jobs.csv'}\n"


def generate_report(data: SDEData, name: str, me: int = 0, te: int = 0, waste: bool = False) -> str:
    tdata, tid, found_bp = find_product_by_name(data, name)
    if not tdata:
        return f"Error: Item '{name}' not found or not published.\n"

    bid = tid if found_bp else None
    disp_tid, disp_tdata = tid, tdata
    if bid:
        disp_tid, disp_tdata = resolve_blueprint_product(data, bid) or (tid, tdata)

    recipe = get_recipe(data, disp_tid, me)
    if not recipe:
        return f"Error: No industry activity found for '{name}'.\n"

    cat, grp = get_group_path(data, disp_tid)
    mg = get_market_group_path(data, disp_tid)
    tech = get_tech_level(data, disp_tid)
    vol = get_volume(data, disp_tid)

    run_time = round(recipe['run_time'] * (1 - te / 100)) if te > 0 else recipe['run_time']

    def mat_row(m):
        mname = get_type_name(data, m['typeID']) or 'Unknown'
        buildable = 'Yes' if any(a in data.buildable_types for a in [m['typeID']]) else 'No'
        if waste:
            return f"| {mname} | {m['quantity']} | {m['original_quantity'] - m['quantity']} | {buildable} |"
        return f"| {mname} | {m['quantity']} | {buildable} |"

    header = "| Item | Quantity | Waste | Buildable |" if waste else "| Item | Quantity | Buildable |"
    sep = "|:-:|:-:|:-:|---:|" if waste else "|:-:|:---:|---:|"

    lines = [
        f"ITEM: {disp_tdata['typeName']} ({disp_tid})",
        f"Group: {cat} > {grp}",
        f"Market Group: {mg if mg else 'None'}",
        f"Tech Level: {tech}",
        f"Volume: {vol:.2f}",
        "",
        "Recipe:",
        f"Activity: {recipe['activity']}",
        f"Output Quantity: {recipe['output_qty']}",
        f"Run Time: {run_time}",
        header,
        sep,
    ]
    for mat in sorted(recipe['materials'], key=lambda m: (get_type_name(data, m['typeID']) or '').lower()):
        lines.append(mat_row(mat))

    return '\n'.join(lines) + '\n'


def main():
    p = argparse.ArgumentParser(description='EVE Online Industrial Planner')
    s = p.add_subparsers(dest='command')

    r = s.add_parser('recipe', help='Generate recipe report')
    r.add_argument('target')
    r.add_argument('--sde', required=True)
    r.add_argument('--me', type=int, default=0)
    r.add_argument('--te', type=int, default=0)
    r.add_argument('--waste', action='store_true')

    inv = s.add_parser('invention', help='Generate invention report')
    inv.add_argument('target')
    inv.add_argument('--sde', required=True)
    inv.add_argument('--skill', type=int, choices=range(1, 6), default=5)

    pl = s.add_parser('plan', help='Create build plan')
    pl.add_argument('build_string')
    pl.add_argument('--config', required=True)
    pl.add_argument('--sde', required=True)
    pl.add_argument('--output', required=True)
    pl.add_argument('--build-all', action='store_true', help='Build all components in the dependency tree')

    args = p.parse_args()
    if not args.command:
        p.print_help()
        sys.exit(1)

    sde_path = Path(args.sde)
    if not sde_path.exists():
        print(f"Error: SDE '{args.sde}' not found.", file=sys.stderr)
        sys.exit(1)

    d = parse_sde(sde_path)

    if args.command == 'recipe':
        if not 0 <= args.me <= 10:
            print(f"Error: ME must be 0-10, got {args.me}", file=sys.stderr)
            sys.exit(1)
        if not 0 <= args.te <= 20 or args.te % 2 != 0:
            print(f"Error: TE must be even 0-20, got {args.te}", file=sys.stderr)
            sys.exit(1)
        print(generate_report(d, args.target, args.me, args.te, args.waste), end='')
    elif args.command == 'invention':
        print(generate_invention_report(d, args.target, args.skill), end='')
    elif args.command == 'plan':
        try:
            params = parse_build_string(args.build_string)
        except ValueError as e:
            print(f"Error: {e}", file=sys.stderr)
            sys.exit(1)
        cfg = load_yaml_file(Path(args.config))
        print(generate_plan(d, params, cfg, Path(args.output)), end='')


if __name__ == '__main__':
    main()

#!/usr/bin/env python3
"""EVE Online Industrial Planner - Parse SDE and emit recipe reports."""

import argparse
import bz2
import csv
import math
import sys
from pathlib import Path
from collections import defaultdict
from dataclasses import dataclass
from typing import Optional, field

import yaml


def load_csv_bz2(filepath: Path):
    with bz2.open(filepath, 'rt', encoding='utf-8') as f:
        return list(csv.DictReader(f))


def load_yaml_file(filepath: Path):
    with open(filepath, 'r', encoding='utf-8') as f:
        return yaml.safe_load(f)


@dataclass
class BuildParams:
    item_name: str
    runs_per_job: int
    num_jobs: int
    me: int = 0
    te: int = 0
    decryptor: str = 'None'
    relic: Optional[str] = None
    build_type: str = 'normal'
    build_all: bool = False


@dataclass
class SDEData:
    types: dict = field(default_factory=dict)
    groups: dict = field(default_factory=dict)
    categories: dict = field(default_factory=dict)
    market_groups: dict = field(default_factory=dict)
    meta_types: dict = field(default_factory=dict)
    meta_groups: dict = field(default_factory=dict)
    activities: dict = field(default_factory=lambda: defaultdict(dict))
    products: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(dict)))
    materials: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(list)))
    probabilities: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(dict)))
    skills: dict = field(default_factory=lambda: defaultdict(lambda: defaultdict(list)))
    activity_names: dict = field(default_factory=dict)
    ship_volumes: dict = field(default_factory=dict)
    buildable_types: set = field(default_factory=set)
    inventable_by_product: dict = field(default_factory=dict)
    blueprint_names: dict = field(default_factory=dict)


def parse_sde(sde_dir: Path) -> SDEData:
    data = SDEData()

    for row in load_csv_bz2(sde_dir / 'invTypes.csv.bz2'):
        if int(row.get('published', 0)) != 1:
            continue
        tid = int(row['typeID'])
        data.types[tid] = {
            'typeID': tid,
            'groupID': int(row['groupID']),
            'typeName': row['typeName'],
            'volume': row.get('volume', '0'),
            'marketGroupID': int(row['marketGroupID']) if row.get('marketGroupID') and row['marketGroupID'] != 'None' else None,
            'mass': row.get('mass', '0'),
            'raceID': row.get('raceID'),
            'basePrice': row.get('basePrice'),
            'description': row.get('description', ''),
        }

    for row in load_csv_bz2(sde_dir / 'invGroups.csv.bz2'):
        if int(row.get('published', 0)) != 1:
            continue
        gid = int(row['groupID'])
        data.groups[gid] = {
            'groupID': gid,
            'categoryID': int(row['categoryID']),
            'groupName': row['groupName'],
            'iconID': row.get('iconID'),
        }

    for row in load_csv_bz2(sde_dir / 'invCategories.csv.bz2'):
        if int(row.get('published', 0)) != 1:
            continue
        cid = int(row['categoryID'])
        data.categories[cid] = {
            'categoryID': cid,
            'categoryName': row['categoryName'],
            'iconID': row.get('iconID'),
        }

    for row in load_csv_bz2(sde_dir / 'invMarketGroups.csv.bz2'):
        mg_id = int(row['marketGroupID'])
        parent_id = int(row['parentGroupID']) if row.get('parentGroupID') and row['parentGroupID'] != 'None' else None
        data.market_groups[mg_id] = {
            'marketGroupID': mg_id,
            'parentGroupID': parent_id,
            'marketGroupName': row['marketGroupName'],
            'description': row.get('description', ''),
            'iconID': row.get('iconID'),
            'hasTypes': int(row.get('hasTypes', 0)) == 1,
        }

    for row in load_csv_bz2(sde_dir / 'invMetaTypes.csv.bz2'):
        if row.get('metaGroupID'):
            data.meta_types[int(row['typeID'])] = int(row['metaGroupID'])

    for row in load_csv_bz2(sde_dir / 'invMetaGroups.csv.bz2'):
        data.meta_groups[int(row['metaGroupID'])] = row['metaGroupName']

    for row in load_csv_bz2(sde_dir / 'industryActivity.csv.bz2'):
        data.activities[int(row['typeID'])][int(row['activityID'])] = int(row['time'])

    for row in load_csv_bz2(sde_dir / 'industryActivityProducts.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        pid = int(row['productTypeID'])
        data.products[tid][aid][pid] = int(row['quantity'])

    for row in load_csv_bz2(sde_dir / 'industryActivityMaterials.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        data.materials[tid][aid].append({'typeID': int(row['materialTypeID']), 'quantity': int(row['quantity'])})

    for row in load_csv_bz2(sde_dir / 'industryActivityProbabilities.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        pid = int(row['productTypeID'])
        data.probabilities[tid][aid][pid] = float(row['probability'])

    for row in load_csv_bz2(sde_dir / 'industryActivitySkills.csv.bz2'):
        tid = int(row['typeID'])
        aid = int(row['activityID'])
        data.skills[tid][aid].append({'skillID': int(row['skillID']), 'level': int(row['level'])})

    for row in load_csv_bz2(sde_dir / 'ramActivities.csv.bz2'):
        if row.get('published') == '1':
            data.activity_names[int(row['activityID'])] = row['activityName']

    data.ship_volumes = {k: float(v) for k, v in load_yaml_file(sde_dir / 'ship_volumes.yaml').items()}

    for tid, acts in data.products.items():
        if 1 in acts or 8 in acts:
            data.buildable_types.add(tid)
        if 8 in acts:
            for pid in acts[8]:
                data.inventable_by_product[pid] = (tid, 8)

    for tid, tdata in data.types.items():
        if 'Blueprint' in tdata['typeName']:
            data.blueprint_names[tdata['typeName']] = tid

    return data


INVENTION = 8
MANUFACTURING = 1


def get_type_name(data: SDEData, tid: int) -> str:
    return data.types.get(tid, {}).get('typeName', '')


def get_group_path(data: SDEData, tid: int):
    tdata = data.types.get(tid)
    if not tdata:
        return 'Unknown', 'Unknown'
    gdata = data.groups.get(tdata['groupID'])
    if not gdata:
        return 'Unknown', 'Unknown'
    if cdata := data.categories.get(gdata['categoryID']):
        return cdata['categoryName'], gdata['groupName']
    return 'Unknown', gdata['groupName']


def get_market_group_path(data: SDEData, tid: int):
    tdata = data.types.get(tid)
    if not tdata or not tdata.get('marketGroupID'):
        return None
    path_parts = []
    mg_id = tdata['marketGroupID']
    while mg_id is not None:
        mgdata = data.market_groups.get(mg_id)
        if not mgdata:
            break
        path_parts.append(mgdata['marketGroupName'])
        mg_id = mgdata.get('parentGroupID')
    return ' > '.join(reversed(path_parts)) if path_parts else None


def get_tech_level(data: SDEData, tid: int) -> str:
    meta_id = data.meta_types.get(tid)
    if not meta_id:
        return 'Tech I'
    meta_name = data.meta_groups.get(meta_id, '')
    return meta_name if meta_name in ('Tech II', 'Tech III') else 'Tech I'


def get_volume(data: SDEData, tid: int) -> float:
    tdata = data.types.get(tid)
    if not tdata:
        return 0.0
    _, gname = get_group_path(data, tid)
    if gname in data.ship_volumes:
        return data.ship_volumes[gname]
    try:
        return float(tdata.get('volume') or '0')
    except ValueError:
        return 0.0


def get_invention_data(data: SDEData, pid: int, skill_level: int) -> Optional[dict]:
    bid, _ = data.inventable_by_product.get(pid, (None, None))
    if not bid:
        return None

    time_minutes = math.ceil(data.activities.get(bid, {}).get(INVENTION, 0) / 60)

    dc_materials = data.materials.get(bid, {}).get(INVENTION, [])
    datacores = []
    for mat in dc_materials:
        mname = get_type_name(data, mat['typeID'])
        if mname and mname.startswith('Datacore - '):
            datacores.append({'typeID': mat['typeID'], 'name': mname, 'quantity': mat['quantity']})

    skill_list = data.skills.get(bid, {}).get(INVENTION, [])
    skills = [{'name': get_type_name(data, s['skillID']), 'required_level': s['level']} for s in skill_list]

    base_prob = data.probabilities.get(bid, {}).get(INVENTION, {}).get(pid, 0.0)

    return {
        'invention_blueprint_id': bid,
        'time_minutes': time_minutes,
        'datacores': datacores,
        'skills': skills,
        'base_probability': base_prob,
        'tech_level': get_tech_level(data, pid)
    }


def get_recipe(data: SDEData, tid: int, me: int = 0) -> Optional[dict]:
    acts = data.products.get(tid, {})
    if MANUFACTURING not in acts:
        return None

    time_raw = data.activities.get(tid, {}).get(MANUFACTURING, 0)
    materials = data.materials.get(tid, {}).get(MANUFACTURING, [])

    if me > 0:
        materials = [{'typeID': m['typeID'], 'quantity': math.ceil(max(1, m['quantity'] * (1 - me / 100))), 'original_quantity': m['quantity']} for m in materials]
    else:
        materials = [{'typeID': m['typeID'], 'quantity': m['quantity'], 'original_quantity': m['quantity']} for m in materials]

    return {
        'activity': data.activity_names.get(MANUFACTURING, 'Manufacturing'),
        'output_qty': sum(acts[MANUFACTURING].values()),
        'run_time': round(time_raw / 60),
        'materials': materials
    }


def find_product_by_name(data: SDEData, name: str, bp_lookup: bool = True):
    for tid, tdata in data.types.items():
        if tdata['typeName'] == name:
            return tdata, tid, False
    if bp_lookup:
        for bp_name, bid in data.blueprint_names.items():
            if bp_name == name:
                return data.types.get(bid), bid, True
    return None, None, False


def calculate_probability(base_prob: float, skill_level: int, decryptor: str) -> float:
    mult = base_prob * (1 + 7 * skill_level / 120)
    dec = DECRYPTORS.get(decryptor, (0, 0, 0, 0))
    return max(0.0, min(1.0, mult * (1 + dec[0] / 100.0)))


DECRYPTORS = {
    'None': (0, 0, 0, 0),
    'Accelerant Decryptor': (20, 1, 2, 10),
    'Attainment Decryptor': (80, 4, -1, 4),
    'Augmentation Decryptor': (-40, 9, -2, 2),
    'Optimized Attainment Decryptor': (90, 2, 1, -2),
    'Optimized Augmentation Decryptor': (-10, 7, 2, 0),
    'Parity Decryptor': (50, 3, 1, -2),
    'Process Decryptor': (10, 0, 3, 6),
    'Symmetry Decryptor': (0, 2, 1, 8),
}


def split_job_runs(total_runs: int, split_days: float, days_per_run: float) -> list[tuple[int, int]]:
    """
    Split a job into multiple jobs based on the split_days threshold.

    Args:
        total_runs: Total number of runs needed
        split_days: Minimum number of days a job must take before being split
        days_per_run: Days per single run (real time after TE reduction)

    Returns:
        List of (runs, count) tuples representing the split jobs

    Formula from specification:
        max_runs = floor(split_days / days_per_run)
        t = ceil(N / max_runs)
        B = N // t
        x = N % t

        if B + 1 == max_runs and x > t/2 and N // (t+1) + 1 < max_runs:
            t = t + 1
            B = N // t
            x = N % t

        output: x jobs of (B+1), (t-x) jobs of B
    """
    # If no runs or days_per_run is 0, return as-is
    if total_runs <= 0 or days_per_run == 0:
        return [(total_runs, 1)]

    # Calculate the threshold based on split_days
    max_days_threshold = min(30, split_days)

    # Check if total time exceeds threshold
    if total_runs * days_per_run <= max_days_threshold:
        return [(total_runs, 1)]

    # Calculate max runs per job before splitting is needed
    max_runs = int(max_days_threshold // days_per_run)

    # Can't split if less than 2 runs or max_runs < 2
    if max_runs < 2:
        return [(total_runs, 1)]

    N = total_runs

    # If total runs don't exceed max_runs, return as-is
    if N <= max_runs:
        return [(N, 1)]

    # Apply the splitting formula
    t = (N + max_runs - 1) // max_runs  # ceil(N / max_runs)
    B = N // t
    x = N % t

    if B + 1 == max_runs and x > t / 2 and N // (t + 1) + 1 < max_runs:
        t = t + 1
        B = N // t
        x = N % t

    result = []
    # x jobs of (B+1) runs
    if x > 0:
        result.append((B + 1, x))
    # (t-x) jobs of B runs
    if t - x > 0:
        result.append((B, t - x))

    return result

TECHIII_RELICS = {'Intact': 0.26, 'Malfunctioning': 0.21, 'Wrecked': 0.14}
TECHIII_BASE_RUNS = {'Intact': 20, 'Malfunctioning': 10, 'Wrecked': 3}


def parse_build_string(build_str: str) -> BuildParams:
    parts = build_str.strip().split()
    if len(parts) < 2:
        raise ValueError(f"Invalid build string format: {build_str}")

    num_jobs = 1
    x_idx = next((i for i, p in enumerate(parts) if p.lower().startswith('x')), -1)
    if x_idx >= 0:
        num_jobs = int(parts[x_idx][1:])
        parts = parts[:x_idx] + parts[x_idx+1:]

    # Find first numeric token
    first_num = next((i for i, p in enumerate(parts) if p.isdigit()), -1)
    if first_num <= 0:
        raise ValueError(f"Invalid build string format: {build_str}")

    item_name = ' '.join(parts[:first_num])
    tokens = parts[first_num:]

    if len(tokens) == 1:
        return BuildParams(item_name, int(tokens[0]), num_jobs)
    if len(tokens) == 2:
        try:
            return BuildParams(item_name, int(tokens[0]), num_jobs, me=int(tokens[1]))
        except ValueError:
            return BuildParams(item_name, int(tokens[0]), num_jobs, decryptor=tokens[1], build_type='invention')
    if len(tokens) == 3:
        return BuildParams(item_name, int(tokens[0]), num_jobs, me=int(tokens[1]), te=int(tokens[2]))
    if len(tokens) == 4:
        return BuildParams(item_name, int(tokens[0]), num_jobs, decryptor=tokens[1], relic=tokens[2], build_type='re')

    raise ValueError(f"Invalid build string format. Unexpected argument count: {build_str}")


def generate_invention_report(data: SDEData, name: str, skill: int) -> str:
    tdata, tid, is_bp = find_product_by_name(data, name)
    if not tdata:
        return f"Error: Item '{name}' not found or not published.\n"

    if is_bp:
        inv = data.products.get(tid, {}).get(INVENTION, {})
        if inv:
            tid = next(iter(inv.keys()))
            tdata = data.types.get(tid)
        else:
            return f"Error: '{name}' is not an inventable blueprint.\n"

    inv = get_invention_data(data, tid, skill)
    if not inv:
        return f"Error: '{name}' is not an inventable item.\n"

    tech = inv['tech_level']
    if tech not in ('Tech II', 'Tech III'):
        return f"Error: '{name}' is not Tech II or Tech III.\n"

    cat, grp = get_group_path(data, tid)
    mg = get_market_group_path(data, tid)

    lines = [
        f"ITEM: {tdata['typeName']} ({tid})",
        f"Group: {cat} > {grp}",
        f"Market Group: {mg if mg else 'None'}",
        f"Tech Level: {tech}",
        "",
        "Invention:",
    ]

    if tech == 'Tech II':
        lines.append(f"Base: {get_type_name(data, inv['invention_blueprint_id'])} ({inv['invention_blueprint_id']})")

    dc = sorted(inv['datacores'], key=lambda d: d['name'].lower())
    lines.append(f"Datacores: {', '.join(d['name'] for d in dc)}")
    lines.append(f"Required Per Run: {dc[0]['quantity'] if dc else 0}")

    sk = sorted(inv['skills'], key=lambda s: s['name'].lower())
    lines.append(f"Skills: {', '.join(s['name'] for s in sk)}")
    lines.append(f"Time: {inv['time_minutes']}")

    if tech == 'Tech II':
        base_bp = inv['invention_blueprint_id']
        base_runs = data.products.get(base_bp, {}).get(INVENTION, {}).get(tid, 10)
        lines.extend(["Probabilities:", "| Decryptor                       | Probability | Runs | ME | TE |", "|---------------------------------|-------------|------|----|----|"])
        for dname in sorted(DECRYPTORS.keys(), key=str.lower):
            prob = calculate_probability(inv['base_probability'], skill, dname)
            _, dr, dme, dte = DECRYPTORS[dname]
            lines.append(f"| {dname:<31} | {prob:>9.2f} | {base_runs + dr:>4} | {2 + dme:>2} | {4 + dte:>2} |")
    else:
        lines.extend(["Probabilities:", "| Invented From                | Decryptor                       | Probability | Runs | ME | TE |", "|------------------------------|---------------------------------|-------------|------|----|----|"])
        for rel in ('Intact', 'Malfunctioning', 'Wrecked'):
            for dname in sorted(DECRYPTORS.keys(), key=str.lower):
                prob = calculate_probability(TECHIII_RELICS[rel], skill, dname)
                _, dr, dme, dte = DECRYPTORS[dname]
                lines.append(f"| {rel:<28} | {dname:<31} | {prob:>9.2f} | {TECHIII_BASE_RUNS[rel] + dr:>4} | {2 + dme:>2} | {4 + dte:>2} |")

    return '\n'.join(lines) + '\n'


def write_jobs_csv(path: Path, name: str, runs: int, days: float, count: int):
    with open(path, 'w', newline='', encoding='utf-8') as f:
        w = csv.writer(f)
        w.writerow(['name', 'runs', 'days', 'count'])
        w.writerow([name, runs, days, count])


def write_materials_csv(path: Path, mat_data: dict):
    with open(path, 'w', newline='', encoding='utf-8') as f:
        w = csv.writer(f)
        w.writerow(['name', 'to_buy', 'buy_volume', 'start_amount', 'end_amount'])
        for name in sorted(mat_data.keys()):
            qty = mat_data[name]
            w.writerow([name, qty, round(qty / 10, 1), 0, 0])


def resolve_blueprint_product(data: SDEData, bid: int):
    for pid, acts in data.products.items():
        if pid == bid:
            for act in acts.values():
                if act:
                    product_id = next(iter(act.keys()))
                    return product_id, data.types.get(product_id)
    return None, None


def generate_plan(data: SDEData, params: BuildParams, config: dict, out_dir: Path) -> str:
    out_dir.mkdir(parents=True, exist_ok=True)

    tdata, tid, found_bp = find_product_by_name(data, params.item_name)
    if not tdata:
        return f"Error: Item '{params.item_name}' not found or not published.\n"

    bid = tid if found_bp else None
    if bid:
        tid, tdata = resolve_blueprint_product(data, bid)
        if not tid:
            return f"Error: No product found for blueprint.\n"

    if params.build_type in ('invention', 're'):
        return _gen_invention_plan(data, params, config, out_dir, tid, bid)
    return _gen_manufacturing_plan(data, params, config, out_dir, tid, bid)


def _gen_invention_plan(data: SDEData, params: BuildParams, config: dict, out_dir: Path, tid: int, bid: int):
    inv = get_invention_data(data, tid, config.get('invention_skill', 3))
    if not inv:
        return f"Error: item not inventable.\n"

    prob = calculate_probability(inv['base_probability'], config.get('invention_skill', 3), params.decryptor)
    _, dr, _, _ = DECRYPTORS.get(params.decryptor, (0, 0, 0, 0))

    rel = params.relic or 'Malfunctioning'
    base_runs = TECHIII_BASE_RUNS.get(rel, 10) if params.build_type == 're' else data.products.get(inv['invention_blueprint_id'], {}).get(INVENTION, {}).get(tid, 10)
    runs = base_runs + dr

    total_runs = params.num_jobs * params.runs_per_job
    exp_bp_runs = math.ceil(total_runs / (runs * prob))

    dc_materials = data.materials.get(inv['invention_blueprint_id'], {}).get(INVENTION, [])
    dc_data = {}
    for mat in dc_materials:
        mname = get_type_name(data, mat['typeID'])
        if mname and mname.startswith('Datacore - '):
            dc_data[mname] = dc_data.get(mname, 0) + mat['quantity'] * exp_bp_runs

    write_materials_csv(out_dir / 'materials.csv', dc_data)

    invent_time = inv['time_minutes'] * exp_bp_runs
    bp_name = get_type_name(data, inv['invention_blueprint_id']) or f"Blueprint {inv['invention_blueprint_id']}"
    write_jobs_csv(out_dir / 'jobs.csv', f"{bp_name} Blueprints", exp_bp_runs, math.ceil(invent_time / 60 / 24 * 100) / 100, 1)

    return f"Plan generated: {out_dir / 'materials.csv'}, {out_dir / 'jobs.csv'}\n"


def _get_component_me_te(data: SDEData, component_tid: int, config: dict) -> tuple[int, int]:
    """
    Get ME/TE for a component. T1 Capital ships as components are assumed to use ME=0 and TE=0.
    Otherwise, use config values or defaults.
    """
    # Check if it's a component (not a final product)
    _, grp_name = get_group_path(data, component_tid)

    # T1 Capital ships as components use ME=0 and TE=0
    if 'Capital' in grp_name or 'Capital' in get_type_name(data, component_tid):
        return (0, 0)

    # Get component-specific ME/TE from config, or use defaults
    component_defaults = config.get('component_bpo_defaults', {})
    me = component_defaults.get('me', 10)
    te = component_defaults.get('te', 20)

    return (me, te)


def _collect_all_buildable_items(data: SDEData, start_tid: int, start_me: int, start_te: int,
                                  config: dict, me_override: Optional[int] = None,
                                  te_override: Optional[int] = None) -> dict[int, dict]:
    """
    Collect all buildable items in the dependency tree.

    Returns a dict mapping tid to:
        {
            'total_runs': int,  # Total runs needed
            'me': int,          # ME value for this component
            'te': int,          # TE value for this component
            'days_per_run': float,  # Days per run with TE
            'name': str,        # Item name
            'bid': int          # Blueprint ID
        }
    """
    items = {}

    # Use BFS to traverse the dependency tree
    queue = [(start_tid, start_me, start_te)]
    visited = set()

    while queue:
        current_tid, current_me, current_te = queue.pop(0)

        if current_tid in visited:
            continue
        visited.add(current_tid)

        # Check if this item is buildable (manufacturing activity)
        recipe = get_recipe(data, current_tid, me_override or current_me)
        if not recipe:
            continue

        # Find the blueprint for this item
        bid = None
        for pid, acts in data.products.items():
            if MANUFACTURING in acts and current_tid in acts[MANUFACTURING]:
                bid = pid
                break

        if not bid:
            continue

        # Calculate days per run with TE
        bp_time = data.activities.get(bid, {}).get(MANUFACTURING, 0)
        if bp_time == 0:
            bp_time = data.activities.get(current_tid, {}).get(MANUFACTURING, 0)

        te_bonus = config.get('te_bonus', 20)
        full_te = bp_time * (1 - current_te / 100) * (1 - te_bonus / 100)
        days_per_run = full_te / 60 / 24

        # Store item info
        items[current_tid] = {
            'total_runs': 0,  # Will be calculated when we know the total demand
            'me': me_override if me_override is not None else current_me,
            'te': te_override if te_override is not None else current_te,
            'days_per_run': days_per_run,
            'name': get_type_name(data, current_tid) or f'Type {current_tid}',
            'bid': bid,
            'recipe_qty': recipe['output_qty'],
            'material_tids': [m['typeID'] for m in recipe['materials']],
        }

        # Add dependencies to queue
        for mat in recipe['materials']:
            mat_tid = mat['typeID']
            # Check if material is buildable
            if mat_tid in data.buildable_types and mat_tid not in visited and mat_tid not in items:
                # Get ME/TE for this component
                comp_me, comp_te = _get_component_me_te(data, mat_tid, config)
                queue.append((mat_tid, comp_me, comp_te))

    return items


def _calculate_total_runs(items: dict[int, dict], start_tid: int, runs_per_job: int, num_jobs: int) -> None:
    """
    Calculate total runs needed for each item based on the final product demand.
    Updates items in place.
    """
    total_output_needed = runs_per_job * num_jobs

    # Calculate needed runs for each item using topological order
    # Build a map of which items depend on which other items
    dependency_map = defaultdict(set)
    for tid, item in items.items():
        for mat_tid in item['material_tids']:
            if mat_tid in items:
                dependency_map[mat_tid].add(tid)

    # Initialize with the final product
    items[start_tid]['total_runs'] = total_output_needed

    # Propagate through the dependency tree using BFS
    queue = [start_tid]
    processed = set()

    while queue:
        current_tid = queue.pop(0)
        if current_tid in processed:
            continue
        processed.add(current_tid)

        # Calculate total demand from dependent items
        if current_tid != start_tid:
            # Sum up all runs needed from dependents
            dependents = dependency_map.get(current_tid, set())
            total_runs = 0
            for dep_tid in dependents:
                if dep_tid in items:
                    # For each dependent, calculate how many runs of current item they need
                    dep_item = items[dep_tid]
                    # Current item is a material in the recipe, so we need to calculate how many
                    # runs of the parent to get enough material
                    # We need to look at the specific material quantity
                    recipe = get_recipe(items[current_tid], items[current_tid]['me']) or {}
                    if recipe:
                        mat_qty = next((m['quantity'] for m in recipe['materials'] if m['typeID'] == current_tid), 0)
                        if mat_qty > 0:
                            # Calculate runs needed for this dependent
                            runs_for_this = (dep_item['total_runs'] * mat_qty + dep_item['recipe_qty'] - 1) // dep_item['recipe_qty']
                    else:
                        # Default calculation - assume 1:1 ratio
                        runs_for_this = dep_item['total_runs']

                    total_runs += runs_for_this

            items[current_tid]['total_runs'] = total_runs

        # Add dependents to queue
        for dep_tid in dependency_map.get(current_tid, set()):
            if dep_tid not in processed:
                queue.append(dep_tid)


def _gen_manufacturing_plan(data: SDEData, params: BuildParams, config: dict, out_dir: Path, tid: int, bid: int):
    # Find blueprint if not provided
    if not bid:
        for pid, acts in data.products.items():
            if MANUFACTURING in acts and tid in acts[MANUFACTURING]:
                bid = pid
                break
        if not bid:
            return f"Error: No manufacturing blueprint found.\n"

    bp_time = data.activities.get(bid, {}).get(MANUFACTURING, 0)
    if bp_time == 0:
        bp_time = data.activities.get(tid, {}).get(MANUFACTURING, 0)

    te_bonus = config.get('te_bonus', 20)
    full_te = bp_time * (1 - params.te / 100) * (1 - te_bonus / 100)
    run_days = full_te / 60 / 24

    materials = [{'typeID': m['typeID'], 'quantity': math.ceil(max(1, m['quantity'] * (1 - params.me / 100))), 'original_quantity': m['quantity']} for m in data.materials.get(bid, {}).get(MANUFACTURING, [])]

    total_runs = params.num_jobs * params.runs_per_job
    mat_total = {}
    for mat in materials:
        name = get_type_name(data, mat['typeID']) or f'Type {mat["typeID"]}'
        mat_total[name] = mat_total.get(name, 0) + mat['quantity'] * total_runs

    write_materials_csv(out_dir / 'materials.csv', mat_total)

    bp_name = get_type_name(data, bid) or f"Blueprint {bid}"
    with open(out_dir / 'jobs.csv', 'w', newline='', encoding='utf-8') as f:
        w = csv.writer(f)
        w.writerow(['name', 'runs', 'days', 'count'])
        for j in range(1, params.num_jobs + 1):
            w.writerow([bp_name, params.runs_per_job, round(run_days * params.runs_per_job, 2), j])

    return f"Plan generated: {out_dir / 'materials.csv'}, {out_dir / 'jobs.csv'}\n"


def generate_report(data: SDEData, name: str, me: int = 0, te: int = 0, waste: bool = False) -> str:
    tdata, tid, found_bp = find_product_by_name(data, name)
    if not tdata:
        return f"Error: Item '{name}' not found or not published.\n"

    bid = tid if found_bp else None
    disp_tid, disp_tdata = tid, tdata
    if bid:
        disp_tid, disp_tdata = resolve_blueprint_product(data, bid) or (tid, tdata)

    recipe = get_recipe(data, disp_tid, me)
    if not recipe:
        return f"Error: No industry activity found for '{name}'.\n"

    cat, grp = get_group_path(data, disp_tid)
    mg = get_market_group_path(data, disp_tid)
    tech = get_tech_level(data, disp_tid)
    vol = get_volume(data, disp_tid)

    run_time = round(recipe['run_time'] * (1 - te / 100)) if te > 0 else recipe['run_time']

    def mat_row(m):
        mname = get_type_name(data, m['typeID']) or 'Unknown'
        buildable = 'Yes' if any(a in data.buildable_types for a in [m['typeID']]) else 'No'
        if waste:
            return f"| {mname} | {m['quantity']} | {m['original_quantity'] - m['quantity']} | {buildable} |"
        return f"| {mname} | {m['quantity']} | {buildable} |"

    header = "| Item | Quantity | Waste | Buildable |" if waste else "| Item | Quantity | Buildable |"
    sep = "|:-:|:-:|:-:|---:|" if waste else "|:-:|:---:|---:|"

    lines = [
        f"ITEM: {disp_tdata['typeName']} ({disp_tid})",
        f"Group: {cat} > {grp}",
        f"Market Group: {mg if mg else 'None'}",
        f"Tech Level: {tech}",
        f"Volume: {vol:.2f}",
        "",
        "Recipe:",
        f"Activity: {recipe['activity']}",
        f"Output Quantity: {recipe['output_qty']}",
        f"Run Time: {run_time}",
        header,
        sep,
    ]
    for mat in sorted(recipe['materials'], key=lambda m: (get_type_name(data, m['typeID']) or '').lower()):
        lines.append(mat_row(mat))

    return '\n'.join(lines) + '\n'


def main():
    p = argparse.ArgumentParser(description='EVE Online Industrial Planner')
    s = p.add_subparsers(dest='command')

    r = s.add_parser('recipe', help='Generate recipe report')
    r.add_argument('target')
    r.add_argument('--sde', required=True)
    r.add_argument('--me', type=int, default=0)
    r.add_argument('--te', type=int, default=0)
    r.add_argument('--waste', action='store_true')

    inv = s.add_parser('invention', help='Generate invention report')
    inv.add_argument('target')
    inv.add_argument('--sde', required=True)
    inv.add_argument('--skill', type=int, choices=range(1, 6), default=5)

    pl = s.add_parser('plan', help='Create build plan')
    pl.add_argument('build_string')
    pl.add_argument('--config', required=True)
    pl.add_argument('--sde', required=True)
    pl.add_argument('--output', required=True)
    pl.add_argument('--build-all', action='store_true', help='Build all components in the dependency tree')

    args = p.parse_args()
    if not args.command:
        p.print_help()
        sys.exit(1)

    sde_path = Path(args.sde)
    if not sde_path.exists():
        print(f"Error: SDE '{args.sde}' not found.", file=sys.stderr)
        sys.exit(1)

    d = parse_sde(sde_path)

    if args.command == 'recipe':
        if not 0 <= args.me <= 10:
            print(f"Error: ME must be 0-10, got {args.me}", file=sys.stderr)
            sys.exit(1)
        if not 0 <= args.te <= 20 or args.te % 2 != 0:
            print(f"Error: TE must be even 0-20, got {args.te}", file=sys.stderr)
            sys.exit(1)
        print(generate_report(d, args.target, args.me, args.te, args.waste), end='')
    elif args.command == 'invention':
        print(generate_invention_report(d, args.target, args.skill), end='')
    elif args.command == 'plan':
        try:
            params = parse_build_string(args.build_string)
        except ValueError as e:
            print(f"Error: {e}", file=sys.stderr)
            sys.exit(1)
        cfg = load_yaml_file(Path(args.config))
        print(generate_plan(d, params, cfg, Path(args.output)), end='')


if __name__ == '__main__':
    main()

